const HOME_CARD_DEFAULT_ORDER = ['status','versus','coop','trophy'];
const HOME_CARD_LABELS = {status:'Din status',versus:'Konkurrér med venner',coop:'Samarbejd med venner',trophy:'Trofæer'};
const HOME_CARD_SELECTORS = {status:'#hero-score-home',versus:'#versus-home-card',coop:'#coop-home-card',trophy:'#trophy-home-card'};
function normalizedHomeCardOrder(order=read(KEYS.homeCardOrder, HOME_CARD_DEFAULT_ORDER)){ const ids=Array.isArray(order)?order:HOME_CARD_DEFAULT_ORDER; return [...ids.filter(id=>HOME_CARD_DEFAULT_ORDER.includes(id)),...HOME_CARD_DEFAULT_ORDER.filter(id=>!ids.includes(id))]; }
function saveHomeCardOrder(order){ save(KEYS.homeCardOrder, normalizedHomeCardOrder(order)); }
function currentHomeCardOrder(){ const page=$('[data-page="today"]'); if(!page) return normalizedHomeCardOrder(); const fromDom=[...page.querySelectorAll('[data-home-card-id]')].map(el=>el.dataset.homeCardId); return normalizedHomeCardOrder(fromDom.length?fromDom:read(KEYS.homeCardOrder, HOME_CARD_DEFAULT_ORDER)); }
function applyHomeCardOrder(){ const page=$('[data-page="today"]'); if(!page||typeof page.appendChild!=="function") return; normalizedHomeCardOrder().forEach(id=>{ const el=$(HOME_CARD_SELECTORS[id]); if(el){ el.dataset.homeCardId=id; page.appendChild(el); } }); }
function homeCardSurface(el){ return el?.id==='hero-score-home' ? el.firstElementChild : el; }
function homeCardMenuHtml(id){ return `<div class="home-card-menu" data-home-menu="${id}"><button type="button" class="home-card-menu-button" aria-label="Åbn menu til flytning af kort" aria-haspopup="menu" aria-expanded="false">⋯</button><div role="menu" aria-label="Flyttemenu for ${HOME_CARD_LABELS[id]}" hidden><button type="button" role="menuitem" data-home-move="up">Flyt op</button><button type="button" role="menuitem" data-home-move="down">Flyt ned</button><button type="button" role="menuitem" data-home-move="reset">Nulstil rækkefølge</button></div></div>`; }
let openHomeCardMenu=null, homeCardMenuBackdrop=null, homeCardMenuPushedState=false, homeCardMenuIgnoreNextPop=false;
function homeCardMoveAvailability(order,id){ const index=order.indexOf(id); return {up:index>0,down:index>=0&&index<order.length-1}; }
function updateHomeCardMoveButtons(menu){ const availability=homeCardMoveAvailability(currentHomeCardOrder(),menu?.dataset?.homeMenu); ['up','down'].forEach(direction=>{ const button=menu?.querySelector?.(`[data-home-move="${direction}"]`); if(button){ button.disabled=!availability[direction]; button.setAttribute('aria-disabled',String(!availability[direction])); } }); }
function decorateHomeCards(){ HOME_CARD_DEFAULT_ORDER.forEach(id=>{ const el=$(HOME_CARD_SELECTORS[id]), surface=homeCardSurface(el); if(!el||!surface||typeof surface.querySelector!=="function"||typeof surface.insertAdjacentHTML!=="function"||surface.querySelector('.home-card-reorder')) return; surface.classList?.add('home-card-reorderable'); surface.insertAdjacentHTML('afterbegin',`<div class="home-card-reorder">${homeCardMenuHtml(id)}</div>`); }); bindHomeCardReorder(); }
function ensureHomeCardMenuBackdrop(){ if(homeCardMenuBackdrop?.isConnected) return homeCardMenuBackdrop; homeCardMenuBackdrop=document.createElement?.('button'); if(!homeCardMenuBackdrop) return null; homeCardMenuBackdrop.type='button'; homeCardMenuBackdrop.className='home-card-menu-backdrop'; homeCardMenuBackdrop.setAttribute('aria-label','Luk flyttemenu'); homeCardMenuBackdrop.onclick=e=>{ consumeInteraction(e); closeHomeCardMenu(); }; document.body?.appendChild?.(homeCardMenuBackdrop); return homeCardMenuBackdrop; }
function closeHomeCardMenu(skipHistory=false){ if(!openHomeCardMenu) return; const menu=openHomeCardMenu, panel=menu.querySelector('[role="menu"]'), btn=menu.querySelector('.home-card-menu-button'); if(panel) panel.hidden=true; btn?.setAttribute('aria-expanded','false'); menu.classList.remove('open'); menu.closest?.('[data-home-card-id]')?.classList?.remove('home-card-menu-open'); homeCardMenuBackdrop?.remove?.(); homeCardMenuBackdrop=null; document.removeEventListener?.('pointerdown',handleHomeCardOutsidePointer,true); document.removeEventListener?.('keydown',handleHomeCardMenuKeydown,true); openHomeCardMenu=null; if(homeCardMenuPushedState&&!skipHistory&&typeof history!=='undefined'&&history?.state?.oneUpHomeCardMenu){ homeCardMenuPushedState=false; homeCardMenuIgnoreNextPop=true; history.back(); } else homeCardMenuPushedState=false; }
function handleHomeCardOutsidePointer(e){ if(openHomeCardMenu&&!openHomeCardMenu.contains(e.target)) closeHomeCardMenu(); }
function handleHomeCardMenuKeydown(e){ if(e.key==='Escape'){ e.preventDefault(); closeHomeCardMenu(); } }
function openHomeCardMoveMenu(menu){ if(!menu) return; if(openHomeCardMenu&&openHomeCardMenu!==menu) closeHomeCardMenu(true); const panel=menu.querySelector('[role="menu"]'), btn=menu.querySelector('.home-card-menu-button'); openHomeCardMenu=menu; updateHomeCardMoveButtons(menu); menu.closest?.('[data-home-card-id]')?.classList?.add('home-card-menu-open'); ensureHomeCardMenuBackdrop(); if(panel) panel.hidden=false; btn?.setAttribute('aria-expanded','true'); menu.classList.add('open'); document.addEventListener?.('pointerdown',handleHomeCardOutsidePointer,true); document.addEventListener?.('keydown',handleHomeCardMenuKeydown,true); if(typeof history!=='undefined'&&history?.pushState&&!history.state?.oneUpHomeCardMenu){ history.pushState({...(history.state||{}),oneUpHomeCardMenu:true},''); homeCardMenuPushedState=true; } setTimeout(()=>panel?.querySelector('[role="menuitem"]:not([disabled])')?.focus?.(),0); }
function toggleHomeCardMoveMenu(menu){ openHomeCardMenu===menu ? closeHomeCardMenu() : openHomeCardMoveMenu(menu); }
function captureHomeCardPositions(){ const page=$('[data-page="today"]'); if(!page) return new Map(); return new Map([...page.querySelectorAll('[data-home-card-id]')].map(el=>[el.dataset.homeCardId,el.getBoundingClientRect?.().top]).filter(([,top])=>Number.isFinite(top))); }
function homeCardFlipDeltas(before,after){ return new Map([...before].map(([id,top])=>[id,top-after.get(id)]).filter(([id,distance])=>after.has(id)&&Number.isFinite(distance)&&Math.abs(distance)>.5)); }
function animateHomeCardReorder(before,movedId){ if(!before.size||window.matchMedia?.('(prefers-reduced-motion: reduce)').matches) return; const page=$('[data-page="today"]'); if(!page) return; const cards=new Map([...page.querySelectorAll('[data-home-card-id]')].map(el=>[el.dataset.homeCardId,el])), after=new Map([...cards].map(([id,el])=>[id,el.getBoundingClientRect?.().top]).filter(([,top])=>Number.isFinite(top))); homeCardFlipDeltas(before,after).forEach((distance,id)=>{ const el=cards.get(id); if(!el) return; el.classList?.add('home-card-moving'); if(id===movedId) el.classList?.add('home-card-moving-active'); const duration=id===movedId?600:520, keyframes=[{transform:`translate3d(0, ${distance}px, 0)`},{transform:'translate3d(0, 0, 0)'}], options={duration,easing:'cubic-bezier(.22,.72,.25,1)',fill:'both'}; let cleaned=false; const cleanup=()=>{ if(cleaned) return; cleaned=true; el.classList?.remove('home-card-moving','home-card-moving-active'); el.style?.removeProperty?.('transform'); el.style?.removeProperty?.('transition'); }; const cleanupTimer=setTimeout(cleanup,duration+100); const finish=()=>{ clearTimeout(cleanupTimer); cleanup(); }; if(typeof el.animate==='function'){ const animation=el.animate(keyframes,options); animation?.addEventListener?.('finish',finish,{once:true}); animation?.addEventListener?.('cancel',finish,{once:true}); if(animation?.finished?.then) animation.finished.then(finish).catch(finish); } else { el.style.transform=keyframes[0].transform; el.style.transition='none'; requestAnimationFrame(()=>{ el.style.transition=`transform ${duration}ms ${options.easing}`; el.style.transform=keyframes[1].transform; }); } }); }
function reorderedHomeCards(order,id,delta){ const next=[...order], i=next.indexOf(id), j=clamp(i+delta,0,next.length-1); if(i<0||i===j) return next; [next[i],next[j]]=[next[j],next[i]]; return next; }
function moveHomeCard(id,delta){ const order=currentHomeCardOrder(), next=reorderedHomeCards(order,id,delta); if(next.every((item,index)=>item===order[index])) return; const before=captureHomeCardPositions(); saveHomeCardOrder(next); applyHomeCardOrder(); decorateHomeCards(); animateHomeCardReorder(before,id); showToast(`${HOME_CARD_LABELS[id]} flyttet ${delta<0?'op':'ned'}.`); }
function resetHomeCardOrder(){ localStorage.removeItem(KEYS.homeCardOrder); applyHomeCardOrder(); decorateHomeCards(); showToast('Rækkefølgen er nulstillet.'); }
function bindHomeCardReorder(){ $$('.home-card-menu-button').forEach(b=>b.onclick=e=>{ consumeInteraction(e); toggleHomeCardMoveMenu(b.closest('.home-card-menu')); }); $$('[data-home-move]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const menu=b.closest('[data-home-menu]'), id=menu?.dataset?.homeMenu, action=b.dataset.homeMove; b.blur?.(); closeHomeCardMenu(); if(action==='reset') resetHomeCardOrder(); else if(id) moveHomeCard(id,action==='up'?-1:1); }); $$('.home-card-menu [role="menu"]').forEach(m=>m.onclick=e=>consumeInteraction(e)); }
if(typeof window!=='undefined') window.addEventListener?.('popstate',e=>{ if(homeCardMenuIgnoreNextPop){ homeCardMenuIgnoreNextPop=false; e.stopImmediatePropagation?.(); } },true);



const NOTIFICATION_CHANNELS = { invitations:'Invitationer', competitions:'Konkurrencer og samarbejder', progress:'Fremskridt', reminders:'Påmindelser' };
const NOTIFICATION_PROMPT_TEXT = { title:'Vil du holde dig opdateret?', body:'Få besked om invitationer, venners aktivitet og vigtige fremskridt i dine konkurrencer og samarbejder.', primary:'Slå notifikationer til', secondary:'Ikke nu' };
function defaultNotificationPrefs(){ return {enabled:false,permission:'unknown',permanentDenied:false,lastPromptDate:'',promptedSituations:{},preferences:{invitations:false,competitions:true,progress:true,dailyReminders:false},dailyReminder:{enabled:false,time:'18:00'},fcm:{tokenRegistered:false,lastTokenHash:''}}; }
function notificationPlugin(){ return typeof window !== 'undefined' ? window.Capacitor?.Plugins?.OneUpNotifications : null; }
function isAndroidApp(){ return !!notificationPlugin(); }
function normalizeNotificationPrefs(raw=read(KEYS.notifications,{})){ const d=defaultNotificationPrefs(), next={...d,...(raw||{}),preferences:{...d.preferences,...((raw||{}).preferences||{})},dailyReminder:{...d.dailyReminder,...((raw||{}).dailyReminder||{})},promptedSituations:{...((raw||{}).promptedSituations||{})},fcm:{...d.fcm,...((raw||{}).fcm||{})}}; if(next.permission==='granted' && !(raw?.preferences && Object.prototype.hasOwnProperty.call(raw.preferences,'invitations'))) next.preferences.invitations = true; next.enabled=next.permission==='granted' && Object.values(next.preferences).some(Boolean); return next; }
function loadNotificationPrefs(){ state.notifications=normalizeNotificationPrefs(); }
function saveNotificationPrefs(){ state.notifications=normalizeNotificationPrefs(state.notifications); save(KEYS.notifications,state.notifications); }
function notificationStatusText(){ if(!isAndroidApp()) return 'Tilgængelig i Android-appen'; const p=state.notifications||defaultNotificationPrefs(); if(p.permission==='granted'&&p.enabled) return 'Notifikationer er slået til'; if(p.permission==='granted') return 'Notifikationer er slået fra'; return 'Tilladelse mangler'; }
async function refreshNotificationPermission(){ loadNotificationPrefs(); const plugin=notificationPlugin(); if(!plugin){ state.notifications.permission='web-unavailable'; saveNotificationPrefs(); return state.notifications; } const res=await plugin.getPermissionStatus?.()||{}; state.notifications.permission=res.status||res.permission||state.notifications.permission; state.notifications.permanentDenied=!!res.permanentDenied; if(state.notifications.permission==='granted') state.notifications.preferences.invitations = state.notifications.preferences.invitations!==false; saveNotificationPrefs(); return state.notifications; }
function canShowNotificationPrompt(situation){ loadNotificationPrefs(); if(!isAndroidApp()||healthConnectIntro) return false; const n=state.notifications, today=todayKey(); if(n.permission==='granted'||n.permanentDenied) return false; if(n.lastPromptDate===today || n.promptedSituations?.[situation]) return false; return !!situation; }
let notificationPrompt=null;
function closeNotificationPrompt(){ if(!notificationPrompt) return; const prev=notificationPrompt.previous; notificationPrompt.overlay?.remove?.(); document.removeEventListener?.('keydown',notificationPromptKeydown,true); notificationPrompt=null; prev?.focus?.(); }
function notificationPromptKeydown(e){ if(e.key==='Escape'){ e.preventDefault(); closeNotificationPrompt(); } }
function showNotificationPrompt(situation){ if(!canShowNotificationPrompt(situation)) return false; const previous=document.activeElement, overlay=document.createElement('div'); overlay.className='modal-backdrop notification-intro'; if(typeof overlay.querySelector!=='function') return false; overlay.innerHTML=`<div class="modal" role="dialog" aria-modal="true" aria-labelledby="notification-intro-title"><h2 id="notification-intro-title">${NOTIFICATION_PROMPT_TEXT.title}</h2><p>${NOTIFICATION_PROMPT_TEXT.body}</p><div class="button-row"><button type="button" data-notification-enable aria-label="Slå OneUp-notifikationer til">${NOTIFICATION_PROMPT_TEXT.primary}</button><button type="button" class="secondary" data-notification-later aria-label="Ikke nu til OneUp-notifikationer">${NOTIFICATION_PROMPT_TEXT.secondary}</button></div></div>`; document.body?.appendChild?.(overlay); notificationPrompt={overlay,previous,situation}; const mark=()=>{ state.notifications.promptedSituations[situation]=new Date().toISOString(); state.notifications.lastPromptDate=todayKey(); saveNotificationPrefs(); };
  overlay.onclick=e=>{ if(e.target===overlay){ mark(); closeNotificationPrompt(); } };
  overlay.querySelector('[data-notification-later]').onclick=()=>{ mark(); closeNotificationPrompt(); };
  overlay.querySelector('[data-notification-enable]').onclick=async()=>{ mark(); closeNotificationPrompt(); await requestNotificationPermissionFromUser(); };
  document.addEventListener?.('keydown',notificationPromptKeydown,true); setTimeout(()=>overlay.querySelector('[data-notification-enable]')?.focus?.(),0); return true; }
function maybePromptForNotifications(situation){ setTimeout(()=>showNotificationPrompt(situation),350); }
async function requestNotificationPermissionFromUser(){ const plugin=notificationPlugin(); loadNotificationPrefs(); if(!plugin) return null; const status=await refreshNotificationPermission(); if(status.permission==='granted') return status; if(status.permanentDenied){ await plugin.openNotificationSettings?.(); return refreshNotificationPermission(); } const res=await plugin.requestPermission?.(); state.notifications.permission=res?.status||res?.permission||'denied'; state.notifications.permanentDenied=!!res?.permanentDenied; if(state.notifications.permission==='granted'){ state.notifications.preferences={...state.notifications.preferences,invitations:true,competitions:true,progress:true}; await registerFcmTokenIfReady(); } saveNotificationPrefs(); renderProfile(); return state.notifications; }
async function openNotificationSettings(){ const plugin=notificationPlugin(); if(plugin?.openNotificationSettings) await plugin.openNotificationSettings(); await refreshNotificationPermission(); renderProfile(); }
async function registerFcmTokenIfReady(){ const plugin=notificationPlugin(); if(!plugin||state.notifications?.permission!=='granted') return null; const res=await plugin.getFcmToken?.(); if(res?.tokenHash){ state.notifications.fcm={tokenRegistered:false,lastTokenHash:res.tokenHash}; saveNotificationPrefs(); } return res; }
function shouldSendDailyReminder(now=new Date(), goalReached=false){ loadNotificationPrefs(); const n=state.notifications; const hhmm=new Intl.DateTimeFormat('da-DK',{hour:'2-digit',minute:'2-digit',hour12:false}).format(now).replace('.',':'); return !!(n.preferences.dailyReminders&&n.dailyReminder.enabled&&n.dailyReminder.time===hhmm&&!goalReached); }
function notificationSettingsHtml(){ loadNotificationPrefs(); if(!isAndroidApp()) return `<section class="notification-settings" aria-label="Notifikationsindstillinger"><p class="connection-status"><strong>Tilgængelig i Android-appen</strong></p><p class="muted">Browser-push er ikke en del af denne version.</p></section>`; const n=state.notifications, status=notificationStatusText(); const row=(k,l)=>checkboxRow(`data-notification-pref="${k}" ${n.preferences[k]?'checked':''} aria-label="${l}"`, l); return `<section class="notification-settings" aria-label="Notifikationsindstillinger"><p class="connection-status" role="status"><strong>${status}</strong></p><div class="button-row"><button type="button" data-notification-request>${n.permanentDenied?'Åbn notifikationsindstillinger':'Slå notifikationer til'}</button>${n.permanentDenied?'<button type="button" class="secondary" data-notification-settings>Åbn notifikationsindstillinger</button>':''}</div>${row('invitations','Invitationer')}${row('competitions','Konkurrencer og samarbejder')}${row('progress','Fremskridt og milepæle')}${row('dailyReminders','Daglige påmindelser')}<label class="field">Klokkeslæt for daglig påmindelse<input type="time" data-daily-reminder-time value="${escapeHtml(n.dailyReminder.time)}" aria-label="Vælg klokkeslæt for daglig påmindelse"></label><p class="muted">Påmindelser bruger telefonens lokale tidszone og springes over, når dagens mål allerede er nået.</p></section>`; }
function bindNotificationSettings(){ $$('[data-notification-request]').forEach(b=>b.onclick=()=> state.notifications?.permanentDenied ? openNotificationSettings() : requestNotificationPermissionFromUser()); $$('[data-notification-settings]').forEach(b=>b.onclick=openNotificationSettings); $$('[data-notification-pref]').forEach(el=>el.onchange=()=>{ loadNotificationPrefs(); state.notifications.preferences[el.dataset.notificationPref]=!!el.checked; state.notifications.dailyReminder.enabled=!!state.notifications.preferences.dailyReminders; saveNotificationPrefs(); }); $$('[data-daily-reminder-time]').forEach(el=>el.onchange=()=>{ loadNotificationPrefs(); state.notifications.dailyReminder.time=el.value||'18:00'; saveNotificationPrefs(); }); }

