async function refreshHealthConnectStatus(){ loadHealthConnectState(); const plugin=healthConnectPlugin(), types=healthConnectRelevantTypes(); if(!plugin){ state.healthConnect={...state.healthConnect,connected:false,status:HEALTH_CONNECT_ANDROID_ONLY,error:''}; saveHealthConnectState(); renderHealthConnectSection(); return state.healthConnect; } try{ const res=await plugin.getStatus({dataTypes:types}); const supported=res.supportedTypes||types, unsupported=res.unsupportedTypes||types.filter(t=>!supported.includes(t)), granted=new Set(res.grantedTypes||[]), missing=new Set(res.missingTypes||supported.filter(t=>!granted.has(t))); state.healthConnect={...state.healthConnect,connected:supported.length>0&&missing.size===0,status:!res.available?'Ikke tilgængelig':(missing.size&&granted.size?'Delvist forbundet':(missing.size?'Ikke forbundet':'Forbundet')),error:res.available?'':(res.message||''),permissions:Object.fromEntries(supported.map(t=>[t,granted.has(t)&&!missing.has(t)])),unsupportedTypes:unsupported,permanentlyDenied:!!res.permanentlyDenied}; saveHealthConnectState(); renderHealthConnectSection(); if(granted.size) await syncHealthConnect({silent:true,dataTypes:supported.filter(t=>granted.has(t))}); }catch(e){ state.healthConnect={...state.healthConnect,status:'Synkroniseringsfejl',error:healthConnectErrorMessage(e),permanentlyDenied:/permanent|indstillinger/i.test(healthConnectErrorMessage(e))}; saveHealthConnectState(); renderHealthConnectSection(); } return state.healthConnect; }
