let healthConnectIntro=null;
function closeHealthConnectIntro(skipHistory=false){ if(!healthConnectIntro) return; const prev=healthConnectIntro.previous; healthConnectIntro.overlay?.remove?.(); document.removeEventListener?.('keydown',healthConnectIntroKeydown,true); healthConnectIntro=null; prev?.focus?.(); if(!skipHistory&&history?.state?.healthConnectIntro) history.back(); }
function healthConnectIntroKeydown(e){ if(e.key==='Escape'){ e.preventDefault(); closeHealthConnectIntro(); } }
async function connectHealthConnect(dataTypes=healthConnectRelevantTypes()){ const plugin=healthConnectPlugin(); if(!plugin){ state.healthConnect={...state.healthConnect,connected:false,status:HEALTH_CONNECT_ANDROID_ONLY,error:''}; saveHealthConnectState(); renderHealthConnectSection(); return; } try{ const status=await plugin.getStatus({dataTypes}); if(!status.available){ state.healthConnect={...state.healthConnect,status:'Ikke tilgængelig',error:status.message||'Health Connect er ikke installeret eller tilgængelig på denne Android-enhed.'}; saveHealthConnectState(); renderHealthConnectSection(); return; } const supported=status.supportedTypes||dataTypes, granted=new Set(status.grantedTypes||[]), missing=(status.missingTypes||supported.filter(t=>!granted.has(t))).filter(t=>supported.includes(t)); if(missing.length){ const permission=await plugin.requestHealthPermissions({dataTypes:missing}); if(permission.permanentlyDenied){ state.healthConnect={...state.healthConnect,permanentlyDenied:true,error:'Android kan ikke vise tilladelsesdialogen igen. Åbn Health Connect-indstillinger og giv OneUp adgang dér.'}; saveHealthConnectState(); renderHealthConnectSection(); return; } } await refreshHealthConnectStatus(); }catch(e){ state.healthConnect={...state.healthConnect,status:'Tilladelse afvist',error:healthConnectErrorMessage(e),permanentlyDenied:/permanent|indstillinger/i.test(healthConnectErrorMessage(e))}; saveHealthConnectState(); renderHealthConnectSection(); } }
async function syncHealthConnect({silent=false,dataTypes=healthConnectRelevantTypes()}={}){ const plugin=healthConnectPlugin(); if(!plugin||!dataTypes.length) return null; try{ const res=plugin.readTodayAggregates?await plugin.readTodayAggregates({dataTypes}):await plugin.readTodaySteps(); const granted=new Set(res.grantedTypes||dataTypes), missing=new Set(res.missingTypes||[]), unsupported=res.unsupportedTypes||[], values={steps:Math.max(0,Number(res.steps)||0),distance:Math.max(0,Number(res.distanceKm)||0),activeCalories:Math.max(0,Number(res.activeCaloriesKcal)||0),exerciseDuration:Math.max(0,Number(res.exerciseDurationMinutes)||0),sleepDuration:Math.max(0,Number(res.sleepDurationHours)||0),restingHeartRate:Math.max(0,Number(res.restingHeartRate)||0),hrv:Math.max(0,Number(res.hrvRmssd)||0),floorsClimbed:Math.max(0,Number(res.floorsClimbed)||0)}; values.stairsUp=stairsUpFromFloors(values.floorsClimbed,userStepsPerFloor()); const now=new Date().toISOString(); state.healthConnect={...state.healthConnect,connected:granted.size>0&&missing.size===0,status:missing.size&&granted.size?'Delvist forbundet':(missing.size?'Tilladelse mangler':'Forbundet'),error:res.error||'',steps:values.steps,values,lastSyncedAt:now,unsupportedTypes:unsupported,availability:Object.fromEntries(Object.entries(values).map(([k,v])=>[k,{dataAvailable:Number(v)>0,checkedAt:now}])),permissions:{...state.healthConnect.permissions,...Object.fromEntries(dataTypes.filter(t=>!unsupported.includes(t)).map(t=>[t,granted.has(t)&&!missing.has(t)]))}}; const add=(type,val)=>{ const act=HEALTH_CONNECT_TYPES[type]?.logActivity; if(granted.has(type) && val>0 && state.activitySettings?.[act]) addEntry(act,{value:val,source:'Health Connect',externalSource:'healthConnect',timestamp:now}); }; add('steps',values.steps); add('distance',values.distance); add('activeCalories',values.activeCalories); add('exerciseDuration',values.exerciseDuration); saveHealthConnectState(); renderHealthConnectSection(); if(!silent) showToast(Object.values(values).some(v=>v>0)?'Health Connect er synkroniseret.':'Tilladelse givet, men ingen data fundet endnu.'); return values; }catch(e){ state.healthConnect={...state.healthConnect,status:'Synkroniseringsfejl',error:healthConnectErrorMessage(e)}; saveHealthConnectState(); renderHealthConnectSection(); if(!silent) showToast(state.healthConnect.error); return null; } }
async function syncHealthConnectSteps(opts={}){ return (await syncHealthConnect({...opts,dataTypes:['steps']}))?.steps ?? null; }
function healthConnectSectionHtml(sectionId='health-connect-section'){ loadHealthConnectState(); const hc=state.healthConnect, plugin=!!healthConnectPlugin(), types=healthConnectRelevantTypes(), missing=types.filter(t=>hc.permissions?.[t]!==true), granted=types.filter(t=>hc.permissions?.[t]===true), full=plugin&&types.length&&missing.length===0, partial=plugin&&granted.length&&missing.length; const rows=types.map(t=>`<li><b>${HEALTH_CONNECT_TYPES[t].label}</b>: ${hc.permissions?.[t]===true?'Kan læses':'Tilladelse mangler'}</li>`).join(''); if(!plugin) return `<article id="${escapeHtml(sectionId)}" class="card health-connect-card connections-card"><h3>Health Connect kræver Android-appen</h3><p class="info-box">Åbn OneUp-appen på din Android-telefon for at forbinde Health Connect og synkronisere dine sundhedsdata automatisk.</p></article>`; const statusText=full?'✓ Health Connect er forbundet':(partial?'! Health Connect er delvist forbundet':(hc.status==='Ikke tilgængelig'?'! Health Connect mangler':'! Health Connect er ikke forbundet')); const action=hc.status==='Ikke tilgængelig'?`<button type="button" data-health-connect-install aria-label="Installer eller opdater Health Connect">Installer eller opdater Health Connect</button>`:(hc.permanentlyDenied?`<button type="button" data-health-connect-settings aria-label="Åbn Health Connect-indstillinger">Åbn Health Connect-indstillinger</button>`:(partial?`<button type="button" data-health-connect-missing aria-label="Giv manglende Health Connect-tilladelser">Giv manglende tilladelser</button>`:`<button type="button" data-health-connect-intro aria-label="Forbind Health Connect">Forbind Health Connect</button>`)); return `<article id="${escapeHtml(sectionId)}" class="card health-connect-card connections-card"><h3>Health Connect</h3><p class="muted">Synkronisér skridt, distance, træningstid, aktive kalorier og etager fra Health Connect.</p><p class="connection-status" role="status" aria-label="Health Connect-status: ${escapeHtml(statusText)}"><strong>${escapeHtml(statusText)}</strong></p>${partial?`<p>OneUp mangler ${missing.length} tilladelser for at kunne måle alle understøttede aktiviteter.</p>`:''}${hc.error?`<p class="error-text" role="status">${escapeHtml(hc.error)}</p>`:''}<p><strong>Seneste vellykkede synkronisering:</strong> ${escapeHtml(healthConnectLastSyncText())}</p><p><strong>Tilgængelige datatyper:</strong> ${escapeHtml(granted.map(t=>HEALTH_CONNECT_TYPES[t].label).join(', ')||'Ingen endnu')}</p>${missing.length?`<details><summary>Se detaljer</summary><ul class="plain-list">${rows}</ul></details>`:''}<div class="button-row">${action}${full?`<button type="button" data-health-connect-sync aria-label="Synkronisér Health Connect nu">Synkronisér nu</button><button type="button" class="secondary" data-health-connect-settings aria-label="Administrér Health Connect-tilladelser">Administrér tilladelser</button>`:''}</div></article>`; }
function bindHealthConnectButtons(){ $$('[data-health-connect-intro]').forEach(b=>b.onclick=()=>showHealthConnectIntro()); $$('[data-health-connect-connect]').forEach(b=>b.onclick=()=>showHealthConnectIntro()); $$('[data-health-connect-missing]').forEach(b=>b.onclick=()=>connectHealthConnect(healthConnectRelevantTypes().filter(t=>state.healthConnect?.permissions?.[t]!==true))); $$('[data-health-connect-sync]').forEach(b=>b.onclick=()=>syncHealthConnect()); $$('[data-health-connect-settings]').forEach(b=>b.onclick=async()=>{ const plugin=healthConnectPlugin(); if(plugin?.openHealthConnectSettings) await plugin.openHealthConnectSettings(); await refreshHealthConnectStatus(); }); $$('[data-health-connect-install]').forEach(b=>b.onclick=async()=>{ const plugin=healthConnectPlugin(); if(plugin?.openHealthConnectInstall) await plugin.openHealthConnectInstall(); await refreshHealthConnectStatus(); }); }
