function copenhagenDateKey(input=new Date()){ const d=input instanceof Date?input:new Date(input); const parts=new Intl.DateTimeFormat('en-CA',{timeZone:APP_TIME_ZONE,year:'numeric',month:'2-digit',day:'2-digit'}).formatToParts(d); const m=Object.fromEntries(parts.map(p=>[p.type,p.value])); return `${m.year}-${m.month}-${m.day}`; }
const todayKey = () => copenhagenDateKey(window.__oneUpNow ? window.__oneUpNow() : new Date());
const oneUpNowMs = () => window.__oneUpNow ? window.__oneUpNow().getTime() : Date.now();
const day = (offset=0, base=todayKey()) => { const d=new Date(`${base}T12:00:00Z`); d.setUTCDate(d.getUTCDate()+offset); return d.toISOString().slice(0,10); };
const num = v => Math.max(0, Number(v)||0); const clamp=(v,min=0,max=100)=>Math.max(min,Math.min(max,v)); const fmt = v => Math.round(v).toLocaleString('da-DK');
function splitDuration(totalMinutes) { const value = Math.max(0, Number(totalMinutes) || 0); return { hours: Math.floor(value / 60), minutes: value % 60 }; }
function combineDuration(hours, minutes) { return Math.max(0, (Number(hours) || 0) * 60 + (Number(minutes) || 0)); }
function formatDuration(totalMinutes) { const { hours, minutes } = splitDuration(totalMinutes); if (hours && minutes) return `${hours} t. ${minutes} min.`; if (hours) return `${hours} t.`; return `${minutes} min.`; }
const durationActivityIds = new Set(['screenFreeBeforeBed','trainingTime','activeMinutesWearable','socialMediaFree','sleepDuration','timeInBed']);
const durationPersonalMetricIds = new Set(['socialMediaTime','totalScreenTime','activeMinutes','sleepDuration']);
function isDurationActivity(id){ return durationActivityIds.has(normalizeActivityId(id)); }
function durationQuickOptions(kind='default'){ if(kind==='screen') return [30,60,120,180]; if(kind==='social') return [15,30,60,120]; if(kind==='sleep') return [420,450,480,540]; if(kind==='training') return [20,30,45,60]; return [30,60,120,180]; }
function durationKindFor(id){ id=normalizeActivityId(id); if(['socialMediaFree','socialMediaTime'].includes(id)) return 'social'; if(['screenFreeBeforeBed','totalScreenTime'].includes(id)) return 'screen'; if(['sleepDuration','timeInBed'].includes(id)) return 'sleep'; return 'training'; }
function hoursToDurationMinutes(value){ return Math.round(num(value)*60); }
