function activityGoalFromDurationMinutes(id,minutes){ return ['sleepDuration','timeInBed'].includes(normalizeActivityId(id)) ? Math.round(num(minutes))/60 : Math.round(num(minutes)); }
function validateDurationInterval(minimumMinutes, maximumMinutes){ return num(maximumMinutes) >= num(minimumMinutes); }
const escapeHtml = v => String(v ?? '').replace(/[&<>'"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch]));
function cmToFeetInches(cm){ const total=Math.round(num(cm)/2.54); return {feet:Math.floor(total/12), inches:total%12}; }
function feetInchesToCm(feet, inches){ return (num(feet)*12 + num(inches)) * 2.54; }
function kgToLb(kg){ return num(kg) * 2.2046226218; }
function lbToKg(lb){ return num(lb) / 2.2046226218; }
function kmToMiles(km){ return num(km) * 0.6213711922; }
function milesToKm(miles){ return num(miles) / 0.6213711922; }
function ageFromBirthDate(birthDate, referenceDate = new Date()){
  if(!/^\d{4}-\d{2}-\d{2}$/.test(birthDate||'')) return null;
  const [y,m,d]=birthDate.split('-').map(Number), ref=new Date(referenceDate);
  let age=ref.getFullYear()-y;
  const hasBirthdayPassed=(ref.getMonth()+1>m)||((ref.getMonth()+1)===m&&ref.getDate()>=d);
  return hasBirthdayPassed ? age : age-1;
}
