function defaultSharing(){ return {shareDailyScores:false,metrics:{steps:true,distance:true,activeMinutes:true,caloriesBurned:true,workouts:true,sleepDuration:true,sleepScore:true,restingHeartRate:false,hrv:false,vo2Max:false,floorsOrElevation:true,oneUpPoints:true}}; }
