function migrateProfileFields(){
  const p=state.profile;
  normalizeSharing();
  if(p.nickname && !p.name) p.name=p.nickname;
  if(p.height && !p.heightCm) p.heightCm=num(p.height);
  if(p.weight && !p.weightKg) p.weightKg=num(p.weight);
  if(p.sex && !p.biologicalSex){ const sex=String(p.sex).toLowerCase(); p.biologicalSex=sex.startsWith('k')||sex==='female'?'female':sex.startsWith('m')||sex==='male'?'male':''; }
  if(p.language && !['da','en'].includes(p.language)) p.language=String(p.language).toLowerCase().startsWith('en')?'en':'da';
  if(p.birthYear && !p.birthDate && !p.legacyBirthYear) p.legacyBirthYear=p.birthYear;
  if(p.country && !p.countryCode){ const wanted=String(p.country).trim().toLowerCase(); const hit=countries.find(([code,name])=>code.toLowerCase()===wanted||name.toLowerCase()===wanted); if(hit) p.countryCode=hit[0]; }
}


