function screenTimeWeekTotal(kind='total',date=todayKey()){ return weekDates(date).reduce((s,d)=>s+screenTimeTotal(kind,d),0); }
function screenTimeSevenDayAverage(kind='total',date=todayKey()){ return Math.round([...Array(7)].reduce((s,_,i)=>s+screenTimeTotal(kind,day(-i,date)),0)/7); }
function screenTimeLastSyncText(){ const at=state?.screenTime?.lastSyncedAt; return at?`Senest synkroniseret kl. ${new Intl.DateTimeFormat('da-DK',{hour:'2-digit',minute:'2-digit',timeZone:APP_TIME_ZONE}).format(new Date(at)).replace(':','.')}`:'Ikke synkroniseret endnu'; }
async function syncScreenTime({silent=false}={}){ const plugin=screenTimePlugin(); if(!plugin){ state.screenTime={...defaultScreenTimeState(),...(state.screenTime||{}),status:'Kun tilgængelig i Android-appen'}; persist(); return null; } try{ const status=await plugin.hasUsageAccess(); if(!status.granted){ state.screenTime={...defaultScreenTimeState(),...(state.screenTime||{}),permissionGranted:false,status:'Adgang mangler',lastSyncedAt:new Date().toISOString()}; persist(); if(!silent) showUsageAccessPrompt(); return null; } analytics.track('usage_access_granted'); const res=await plugin.queryUsageStats({excludePackages:['dk.oneup.app','com.android.systemui','android']}); return storeScreenTimeResult({...res,granted:true}); }catch(e){ state.screenTime={...defaultScreenTimeState(),...(state.screenTime||{}),lastError:String(e?.message||e),status:'Ingen data endnu'}; persist(); if(!silent) showToast('Skærmtid kunne ikke synkroniseres.'); return null; } }
async function requestUsageAccess(){ analytics.track('usage_access_requested'); const plugin=screenTimePlugin(); try{ if(plugin?.openUsageAccessSettings) await plugin.openUsageAccessSettings(); }catch(e){ showToast('Android-indstillinger kunne ikke åbnes. Åbn Usage Access manuelt.'); } }
function showUsageAccessPrompt(){ document.body?.insertAdjacentHTML?.('beforeend',`<div id="usage-access-prompt" class="modal" role="dialog" aria-modal="true"><div class="modal-card"><h2>Giv adgang til skærmtid</h2><p>OneUp skal have adgang til Androids brugsdata for automatisk at kunne måle, hvor længe apps bruges. Dataene behandles lokalt på din telefon.</p><div class="button-row"><button data-open-usage-access>Åbn adgang til brugsdata</button><button class="secondary" data-close-usage-access>Ikke nu</button></div></div></div>`); $('#usage-access-prompt [data-open-usage-access]')?.addEventListener?.('click',()=>{ $('#usage-access-prompt')?.remove(); requestUsageAccess(); }); $('#usage-access-prompt [data-close-usage-access]')?.addEventListener?.('click',()=>$('#usage-access-prompt')?.remove()); }
function screenTimeHomeCard(){ const enabled=['totalScreenTime','socialMediaFree','streamingTime'].some(id=>state.activitySettings?.[id]?.enabled || state.personalGoals?.[{totalScreenTime:'totalScreenTime',socialMediaFree:'socialMediaTime',streamingTime:'streamingTime'}[id]]?.enabled); if(!enabled) return ''; return `<article class="card screen-time-card"><div class="card-head"><div><p class="eyebrow">Skærmtid i dag</p><h3>Skærmtid i dag</h3></div><span>📱</span></div><div class="screen-time-compact"><span><b>${formatDuration(screenTimeTotal('total'))}</b><small>Samlet</small></span><span><b>${formatDuration(screenTimeTotal('social'))}</b><small>Sociale medier</small></span><span><b>${formatDuration(screenTimeTotal('streaming'))}</b><small>Streaming</small></span></div><p class="muted">${escapeHtml(state.screenTime?.status||'Adgang mangler')} · ${escapeHtml(screenTimeLastSyncText())}</p><div class="button-row"><button type="button" data-open-screen-time>Detaljer</button><button type="button" class="secondary" data-sync-screen-time>Opdater</button></div></article>`; }
function screenTimeDetailsHtml(){ const apps=(state.screenTime?.apps||[]).slice().sort((a,b)=>b.foregroundTimeMs-a.foregroundTimeMs); return `<article class="card screen-time-detail"><div class="card-head"><div><p class="eyebrow">Privat og lokalt</p><h2>Skærmtid</h2></div><button class="secondary" data-screen-time-close>Tilbage</button></div><p class="info-box">Package names, appnavne og præcise brugstider gemmes lokalt og sendes ikke til analytics, Firebase eller andre tjenester. Deaktivering af Usage Access stopper fremtidig måling.</p><p><b>I dag:</b> ${formatDuration(screenTimeTotal('total'))} · <b>Seneste 7 dage:</b> ${formatDuration(screenTimeWeekTotal('total'))} · <b>7-dages snit:</b> ${formatDuration(screenTimeSevenDayAverage('total'))}</p><p>${escapeHtml(screenTimeLastSyncText())}</p><div class="button-row"><button data-sync-screen-time>Synkronisér nu</button><button class="secondary" data-open-usage-settings>Administrér appkategorier</button><button class="secondary" data-delete-screen-time>Slet mine skærmtidsdata</button></div><ul class="plain-list">${apps.map(a=>`<li><b>${escapeHtml(a.appLabel||a.packageName)}</b><br><small>${escapeHtml(a.packageName)} · ${formatDuration(Math.round(a.foregroundTimeMs/60000))} · ${escapeHtml(appCategory(a.packageName))}</small></li>`).join('')||'<li>Kan ikke måles endnu</li>'}</ul></article>`; }
function openScreenTimeDetails(){ const host=$('#hero-score-home'); if(host){ host.innerHTML=screenTimeDetailsHtml(); bindScreenTimeButtons(); } }
function openCategoryManager(){ const apps=(state.screenTime?.apps||[]).slice().sort((a,b)=>(a.appLabel||a.packageName).localeCompare(b.appLabel||b.packageName)); const html=`<article class="card"><div class="card-head"><h2>Administrér appkategorier</h2><button class="secondary" data-screen-time-close>Tilbage</button></div><p class="muted">Dine manuelle valg har altid prioritet over standardlisten. YouTube kan flyttes mellem social, streaming eller andet.</p>${apps.map(a=>`<label class="field">${escapeHtml(a.appLabel||a.packageName)}<select data-app-category="${escapeHtml(a.packageName)}">${SCREEN_TIME_CATEGORIES.map(c=>`<option ${appCategory(a.packageName)===c?'selected':''}>${c}</option>`).join('')}</select></label>`).join('')||'<p>Ingen apps registreret endnu.</p>'}<div class="button-row"><button data-reset-categories>Nulstil til standardkategorier</button></div></article>`; const host=$('#hero-score-home'); if(host){ host.innerHTML=html; bindScreenTimeButtons(); } }
function bindScreenTimeButtons(){ $$('[data-open-screen-time]').forEach(b=>b.onclick=openScreenTimeDetails); $$('[data-sync-screen-time]').forEach(b=>b.onclick=()=>syncScreenTime()); $$('[data-open-usage-settings]').forEach(b=>b.onclick=openCategoryManager); $$('[data-delete-screen-time]').forEach(b=>b.onclick=()=>{ state.screenTime=defaultScreenTimeState(); persist(); render(); }); $$('[data-screen-time-close]').forEach(b=>b.onclick=render); $$('[data-reset-categories]').forEach(b=>b.onclick=()=>{ state.screenTimeCategories={overrides:{}}; persist(); openCategoryManager(); }); $$('[data-app-category]').forEach(s=>s.onchange=()=>{ state.screenTimeCategories.overrides[s.dataset.appCategory]=s.value; if(state.screenTime?.apps) storeScreenTimeResult({granted:state.screenTime.permissionGranted,apps:state.screenTime.apps,startTimeMs:state.screenTime.periodStartMs,endTimeMs:state.screenTime.periodEndMs}); openCategoryManager(); }); }

const analytics = { track(event, props={}){ const allowed=['usage_access_requested','usage_access_granted','screen_time_goal_created','app_open','onboarding_completed','first_goal_created','health_connect_permission_granted','first_automatic_data_received','daily_goal_completed','daily_mission_completed','streak_started','streak_extended','rescue_day_used','weekly_reward_unlocked','friend_invite_started']; if(!allowed.includes(event)) return; const safe={}; ['source','period','missionType','rewardType'].forEach(k=>{ if(props[k]) safe[k]=String(props[k]).slice(0,40); }); const list=read(KEYS.analytics,[]); list.push({event,props:safe,at:new Date().toISOString(),localDate:todayKey()}); save(KEYS.analytics,list.slice(-300)); }};
function defaultRetentionState(){ return {version:1,xp:{total:0,grants:{}},goals:{},streak:{current:0,best:0,lastChecked:null,rescues:{},message:''},weekly:{},missions:{},opened:{}}; }
function levelForXp(xp){ let level=1, needed=100, spent=0; while(xp>=spent+needed){ spent+=needed; level++; needed=Math.round(100*Math.pow(level,1.35)); } return {level,totalXp:xp,current:xp-spent,next:needed,remaining:Math.max(0,spent+needed-xp),percent:Math.round((xp-spent)/needed*100)}; }
function grantXp(key, amount){ state.retention ||= defaultRetentionState(); state.retention.xp ||= {total:0,grants:{}}; if(state.retention.xp.grants[key]) return false; state.retention.xp.grants[key]={amount,at:new Date().toISOString()}; state.retention.xp.total+=amount; return true; }
function periodKeyForGoal(id,date=todayKey()){ const m=personalMetrics[id], a=m?.activity; const period=activities[a]?.period==='week'?'week':'day'; return period==='week'?`${copenhagenWeekInfo(date).year}-W${String(copenhagenWeekInfo(date).week).padStart(2,'0')}`:date; }
function retentionGoalRows(date=todayKey()){ normalizePersonalGoals(); return Object.entries(personalMetrics).map(([id,m])=>{ const g=state.personalGoals[id]||{}; if(!personalMetricEnabled(id,m,g)) return null; const value=personalMetricValue(id,date), status=personalGoalStatus(id,value,g); return {id,m,g,value,status,period:activities[m.activity]?.period==='week'?'uge':'dag',key:periodKeyForGoal(id,date)}; }).filter(Boolean); }
function updateRetention(date=todayKey()){ state.retention ||= defaultRetentionState(); analytics.track('app_open'); const rows=retentionGoalRows(date); rows.forEach(r=>{ if(!r.value.available) return; const progressXp=Math.floor(clamp(r.status.progressPercent,0,100)/10)*2; if(progressXp) grantXp(`progress:${r.id}:${date}:${progressXp}`, progressXp); if(r.status.reached===true && grantXp(`complete:${r.id}:${r.key}`, 40)){ analytics.track('daily_goal_completed',{period:r.period}); queueCelebration(`${r.m.icon} ${r.m.title}`, `Du nåede ${personalGoalValueText(r.id,r.value,r.g)}.`, nextMilestoneText(r)); } }); const minimum=rows.find(r=>r.id==='steps')||rows[0]; updateRetentionStreak(minimum,date); updateDailyMission(rows,date); updateWeeklyReward(rows,date); }
function weekId(date=todayKey()){ const w=copenhagenWeekInfo(date); return `${w.year}-W${String(w.week).padStart(2,'0')}`; }
function updateRetentionStreak(row,date=todayKey()){ const s=state.retention.streak ||= {current:0,best:0,lastChecked:null,rescues:{},message:''}; const met=!!row?.status?.reached; if(s.lastChecked===date && (!met || s.current>0)) return; const yesterday=day(-1,date), had=!!s.current; if(met){ s.current=(s.lastChecked===yesterday?s.current:0)+1; s.best=Math.max(s.best,s.current); s.message=s.current===1?'Din streak er startet flot.':'Din streak blev forlænget.'; analytics.track(s.current===1?'streak_started':'streak_extended'); }
 else if(had && s.lastChecked===yesterday && !s.rescues[weekId(yesterday)]){ s.rescues[weekId(yesterday)]=yesterday; s.current+=1; s.best=Math.max(s.best,s.current); s.message='Redningsdagen holdt din streak i live – roligt videre i dag.'; analytics.track('rescue_day_used'); }
 else if(s.lastChecked) { s.current=0; s.message='Ny dag, ny chance for en god serie.'; }
 s.lastChecked=date; }
function missionForDate(rows,date=todayKey()){ const steps=rows.find(r=>r.id==='steps'); if(steps&&steps.value.available&&!steps.status.reached) return {type:'steps_more',text:'Gå 1.000 skridt mere end nu',target:num(steps.value.value)+1000,metric:'steps'}; if(rows.some(r=>r.status.reached!==true)) return {type:'one_goal',text:'Gennemfør ét personligt mål',metric:'any'}; return {type:'steady',text:'Hold din gode rytme resten af dagen',metric:'any'}; }
function updateDailyMission(rows,date=todayKey()){ const m=state.retention.missions[date] ||= missionForDate(rows,date); const done=m.metric==='steps'?num(personalMetricValue('steps',date).value)>=num(m.target):rows.some(r=>r.status.reached===true); if(done&&!m.completedAt){ m.completedAt=new Date().toISOString(); if(grantXp(`mission:${date}`,30)) analytics.track('daily_mission_completed',{missionType:m.type}); queueCelebration('Daglig mission', `${m.text} er klaret.`, 'Næste milepæl: hold streaken i live.'); } }
function updateWeeklyReward(rows,date=todayKey()){ const wk=weekId(date), w=state.retention.weekly[wk] ||= {activeDays:{},goals:0,unlocked:false}; if(rows.some(r=>r.value.available)) w.activeDays[date]=true; w.goals=weekDates(date).reduce((sum,d)=>sum+retentionGoalRows(d).filter(r=>r.status.reached===true).length,0); const progress=Object.keys(w.activeDays).length+w.goals; if(progress>=5&&!w.unlocked){ w.unlocked=true; w.badge='Stabil start'; grantXp(`weekly:${wk}`,75); analytics.track('weekly_reward_unlocked',{rewardType:'xp_badge'}); queueCelebration('Ugentligt trofæ', 'Du låste ugens kiste op.', 'Næste milepæl: 3 aktive dage mere.'); } }
let celebrationQueue=[]; function queueCelebration(title,body,next){ celebrationQueue.push({title,body,next}); }
function nextMilestoneText(r){ return r.id==='steps'?'Næste lille milepæl: 500 ekstra skridt.':'Næste lille milepæl: gentag i morgen.'; }
function retentionStats(days,date=todayKey()){ const dates=Array.from({length:days},(_,i)=>day(-i,date)); return {active:dates.filter(d=>retentionGoalRows(d).some(r=>r.value.available)).length,goals:dates.reduce((s,d)=>s+retentionGoalRows(d).filter(r=>r.status.reached===true).length,0),xp:Object.entries(state.retention?.xp?.grants||{}).filter(([,g])=>dates.includes(copenhagenDateKey(g.at))).reduce((s,[,g])=>s+num(g.amount),0)}; }

const read = (k,f) => { try { return JSON.parse(localStorage.getItem(k)) ?? f; } catch { return f; } }; const save=(k,v)=>localStorage.setItem(k,JSON.stringify(v));
