function firebaseErrorMessage(error){ const code=error?.code||''; if(code.includes('email-already-in-use')) return 'E-mailadressen er allerede i brug.'; if(code.includes('wrong-password')||code.includes('invalid-credential')||code.includes('user-not-found')) return 'E-mail eller adgangskode er forkert.'; if(code.includes('weak-password')) return 'Adgangskoden skal være mindst 6 tegn.'; if(code.includes('invalid-email')) return 'Indtast en gyldig e-mailadresse.'; if(code.includes('requires-recent-login')) return 'Af sikkerhedshensyn skal du logge ind igen, før kontoen kan slettes.'; return 'Der kunne ikke oprettes forbindelse. Prøv igen.'; }
async function ensureUserDocument(user){ const fb=await loadFirebaseApi(); if(!user?.uid) return; await fb.setDoc(fb.doc(fb.db,'users',user.uid),{displayName:user.displayName||'',email:user.email||'',updatedAt:fb.serverTimestamp(),lastSyncedAt:fb.serverTimestamp(),schemaVersion:DATA_VERSION,emailVerified:!!user.emailVerified},{merge:true}); }
async function pullCloudData(user=state.auth?.user){ const fb=await loadFirebaseApi(); if(!user?.uid) return; try{ const snap=await fb.getDoc(fb.doc(fb.db,'users',user.uid,'appData','main')); if(snap.exists()) mergeCloudSnapshot(snap.data()?.data||{}); state.auth.syncStatus='Synkroniseret'; state.auth.lastSyncedAt=new Date().toISOString(); renderAccountSummary(); }catch{ state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkronisering mislykkedes'; renderAccountSummary(); } }
function scheduleCloudSync(delay=1200){ if(!state?.auth?.user?.uid || !firebaseApi) return; clearTimeout(cloudSyncTimer); state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkroniserer…'; cloudSyncTimer=setTimeout(syncToCloud,delay); renderAccountSummary(); }
async function syncToCloud(){ if(cloudSyncInProgress || !state.auth?.user?.uid) return; cloudSyncInProgress=true; try{ const fb=await loadFirebaseApi(), uid=state.auth.user.uid; await fb.setDoc(fb.doc(fb.db,'users',uid,'appData','main'),{data:localSnapshot(),updatedAt:fb.serverTimestamp(),lastSyncedAt:fb.serverTimestamp(),schemaVersion:DATA_VERSION},{merge:true}); await ensureUserDocument(state.auth.user); state.auth.syncStatus='Synkroniseret'; state.auth.lastSyncedAt=new Date().toISOString(); }catch{ state.auth.syncStatus=navigator.onLine===false?'Offline':'Synkronisering mislykkedes'; setTimeout(()=>scheduleCloudSync(5000),5000); } finally{ cloudSyncInProgress=false; renderAccountSummary(); } }
async function maybePromptMigration(user){ const migration=read(KEYS.migration,{}); if(migration[user.uid]?.localMigrationCompleted || !hasLocalOneUpData()) return; openMigrationDialog(user); }
function openMigrationDialog(user){ if($('#migration-dialog')) return; document.body.insertAdjacentHTML('beforeend',`<div id="migration-dialog" class="modal"><div class="modal-card"><h2>Du har fremskridt gemt på denne enhed.</h2><p>Vil du gemme dem på din konto?</p><div class="button-row"><button data-migrate-cloud>Gem på min konto</button><button class="secondary" data-keep-cloud>Behold cloud-data</button><button class="secondary" data-cancel-migration>Annuller</button></div></div></div>`); const d=$('#migration-dialog'); d.querySelector('[data-cancel-migration]').onclick=()=>d.remove(); d.querySelector('[data-keep-cloud]').onclick=()=>{ const m=read(KEYS.migration,{}); m[user.uid]={localMigrationCompleted:true,keptCloudData:true,installId:getInstallId(),date:new Date().toISOString()}; save(KEYS.migration,m); d.remove(); pullCloudData(user); }; d.querySelector('[data-migrate-cloud]').onclick=async()=>{ save(KEYS.localBackup,localSnapshot()); if(!validateSnapshot(localSnapshot())){ showToast('Lokale data kunne ikke valideres.'); return; } await syncToCloud(); const m=read(KEYS.migration,{}); m[user.uid]={localMigrationCompleted:true,installId:getInstallId(),date:new Date().toISOString()}; save(KEYS.migration,m); d.remove(); showToast('Dine lokale fremskridt er gemt på kontoen.'); }; }
function authStatusHtml(){ const u=state.auth?.user; if(!u) return `<p class="muted">Kun gemt på denne enhed</p><p>Gem og synkronisér dine fremskridt mellem enheder.</p><div class="button-row"><button data-auth-open="signup">Opret gratis konto</button><button class="secondary" data-auth-open="login">Log ind</button><button class="secondary" data-auth-guest>Fortsæt som gæst</button></div>`; return `<p><b>${escapeHtml(u.displayName||state.profile.name||'OneUp-bruger')}</b><br>${escapeHtml(u.email||'')}</p><p class="muted">E-mail: ${u.emailVerified?'bekræftet':'ikke bekræftet'} · ${state.auth.syncStatus||'Synkroniseret'}</p>`; }
