function openAuthDialog(mode='login'){ $('#auth-dialog')?.remove(); const signup=mode==='signup', reset=mode==='reset'; document.body.insertAdjacentHTML('beforeend',`<div id="auth-dialog" class="modal"><div class="modal-card auth-card"><button class="secondary" data-auth-close>← Luk</button><h2>${signup?'Opret gratis konto':reset?'Glemt adgangskode':'Log ind'}</h2><p class="muted">Gem og synkronisér dine fremskridt mellem enheder</p><form id="auth-form">${signup?'<label class="field">Navn<input name="name" autocomplete="name"></label>':''}<label class="field">E-mail<input name="email" type="email" autocomplete="email"></label>${reset?'':'<label class="field">Adgangskode<input name="password" type="password" autocomplete="current-password"></label>'}${signup?'<label class="field">Gentag adgangskode<input name="repeat" type="password"></label>':''}<p class="error" id="auth-error"></p><button type="submit">${signup?'Opret konto':reset?'Send nulstillingsmail':'Log ind'}</button></form>${!reset?'<button class="secondary" data-auth-open="reset">Glemt adgangskode</button>':''}</div></div>`); const d=$('#auth-dialog'); d.querySelector('[data-auth-close]').onclick=()=>d.remove(); d.querySelectorAll('[data-auth-open]').forEach(b=>b.onclick=()=>openAuthDialog(b.dataset.authOpen)); d.querySelector('#auth-form').onsubmit=async e=>{ e.preventDefault(); const fd=new FormData(e.target), email=String(fd.get('email')||'').trim(), password=String(fd.get('password')||''), err=$('#auth-error'); if(!email.includes('@')){err.textContent='Indtast en gyldig e-mailadresse.';return;} if(!reset && password.length<6){err.textContent='Adgangskoden skal være mindst 6 tegn.';return;} if(signup && password!==String(fd.get('repeat')||'')){err.textContent='Adgangskoderne er ikke ens.';return;} try{ const fb=await loadFirebaseApi(); if(signup){ const cred=await fb.createUserWithEmailAndPassword(fb.auth,email,password); await fb.updateProfile(cred.user,{displayName:String(fd.get('name')||'').trim()}); await fb.sendEmailVerification(cred.user); showToast('Konto oprettet. Vi har sendt en bekræftelsesmail.'); } else if(reset){ await fb.sendPasswordResetEmail(fb.auth,email); showToast('Hvis adressen er registreret, er der sendt en mail med et link til at vælge en ny adgangskode.'); } else await fb.signInWithEmailAndPassword(fb.auth,email,password); d.remove(); }catch(ex){ err.textContent=firebaseErrorMessage(ex); } }; }
async function resendVerification(){ try{ const fb=await loadFirebaseApi(); if(fb.auth.currentUser){ await fb.sendEmailVerification(fb.auth.currentUser); showToast('Bekræftelsesmail sendt igen.'); }}catch(e){ showToast(firebaseErrorMessage(e)); } }
