async function deleteAccountAndData(){ if(!confirm('Dette sletter din konto og dine synkroniserede OneUp-data permanent. Fortsæt?')) return; if(!confirm('Skriv OK for endeligt at slette konto og cloud-data.')) return; try{ const fb=await loadFirebaseApi(), user=fb.auth.currentUser; if(!user?.uid) return; const col=await fb.getDocs(fb.collection(fb.db,'users',user.uid,'appData')); await Promise.all(col.docs.map(x=>fb.deleteDoc(x.ref))); await fb.deleteDoc(fb.doc(fb.db,'users',user.uid)); await fb.deleteUser(user); showToast('Kontoen og synkroniserede data er slettet.'); }catch(e){ showToast(firebaseErrorMessage(e)); } }
