function recalcSilently(){ Object.values(state.history).forEach(r=>{r.activityPoints={};r.totalPoints=0}); state.log.forEach(e=>{const d=effectiveDate(e); const r=state.history[d] ||= {date:d,activityPoints:{}}; const p=pointsForEntry(e); r.activityPoints[e.activity]=(r.activityPoints[e.activity]||0)+p;}); Object.entries(state.history).forEach(([d,r])=>{r.totalPoints=Object.values(r.activityPoints||{}).reduce((s,v)=>s+num(v),0); r.oneUpScore=oneUpScore(d);}); state.points=Object.values(state.history).reduce((s,r)=>s+num(r.totalPoints),0); }
