function manualAdd(id,b){ if(id==='sleepDuration'){ const start=$('[data-sleep-start]').value, end=$('[data-sleep-end]').value, [sh,sm]=start.split(':').map(Number), [eh,em]=end.split(':').map(Number); let h=(eh+em/60)-(sh+sm/60); if(h<0) h+=24; addEntry(id,{value:h,hours:h,start,end,sleepDate:todayKey()}); return; } const input=$(`[data-input="${id}"]`); if(isBodyMeasurement(id)){ addBodyMeasurement(id,input?.value,todayKey()); return; } addEntry(id,{value:isSessionGoalActivity(id)?Math.max(1,num(b.dataset.value ?? input?.value)||1):num(b.dataset.value ?? input?.value), completedCount:isSessionGoalActivity(id)?Math.max(1,num(b.dataset.value ?? input?.value)||1):undefined, targetCount:isSessionGoalActivity(id)?targetCountFor(id):undefined, goalPeriod:isSessionGoalActivity(id)?goalPeriodFor(id):undefined, activityType:id==='stairs'?'stairs':undefined, direction:id==='stairs'?stairsDirectionFor(id):undefined, timestamp:new Date().toISOString(), distance:num($(`[data-distance="${id}"]`)?.value)}); }

function activeActivityIds(){ return Object.keys(activities).filter(id=>activityCanToggle(id)&&state.activitySettings[id]?.enabled); }
function userName(){ return state.profile.nickname || 'Dig'; }
function demoParticipants(){ return [{id:'amina',name:'Amina',demo:true,friend:true},{id:'jonas',name:'Jonas',demo:true,friend:true},{id:'sofie',name:'Sofie',demo:true,friend:false}]; }
function defaultWeights(ids){ if(!ids.length) return {}; const base=Math.floor(10000/ids.length)/100, weights=Object.fromEntries(ids.map(id=>[id,base])); weights[ids[0]]=Math.round((100-base*(ids.length-1))*100)/100; return weights; }
function sanitizeActivityIds(ids){ return [...new Set((ids||[]).map(id=>id==='steps'?'dailyStepTarget':normalizeActivityId(id)).filter(id=>allActivities[id]))]; }
function isDeprecatedActivity(id){ return !!deprecatedActivities[normalizeActivityId(id)]; }
function activityMeta(id){ return allActivities[normalizeActivityId(id)] || {id,name:id,icon:'•',description:''}; }

const periodLabels={daily:'pr. dag',averageDaily:'gennemsnit pr. dag',weekly:'pr. uge',competition:'hele konkurrencen',day:'pr. dag',week:'pr. uge'};
const metricUnits={steps:'skridt',sets:'sæt',minutes:'minutter',kilometers:'km',workouts:'træningspas',hours:'timer'};
function baseGoalConfig(id){
  id=normalizeActivityId(id);
  const s=state?.activitySettings?.[id]||{}, a=activityMeta(id);
  if(isDeprecatedActivity(id)) return {activityId:id,metric:'legacy',period:'daily',target:num(s.goal||1),bonusTarget:null,unit:a.unit||'',comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true,deprecated:true,migrationNotice:'Denne aktivitet bruges ikke længere i nye konkurrencer.'};
  if(id==='mostSteps') return {activityId:id,metric:'steps',unit:'skridt',period:'averageDaily',target:0,bonusTarget:null,comparisonMode:'ranking',scoringMethod:'ranking',legacyDefault:true,complete:true};
  if(id==='dailyStepTarget') return {activityId:id,metric:'steps',unit:'skridt',period:'daily',target:num(s.goal||8000),bonusTarget:null,comparisonMode:'completedDays',scoringMethod:'completedDays',legacyDefault:true};
  if(id==='bedtime') return {activityId:id,metric:'time',unit:'kl.',target:num(s.goal||22.25),bonusTarget:null,comparisonMode:'earlierThanTarget',scoringMethod:'earlierThanTarget',period:'daily',legacyDefault:true};
  if(id==='running'||id==='cycling') return {activityId:id,metric:'kilometers',unit:'km',period:'weekly',target:num(s.goal||a.goal||1),bonusTarget:null,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
  if(id==='socialMediaFree') return {activityId:id,metric:'minutes',unit:'minutter',period:'daily',target:num(s.goal||60),bonusTarget:null,comparisonMode:'lessIsBetter',scoringMethod:'lessIsBetter',legacyDefault:true};
  return {activityId:id,metric:a.unit==='skridt'?'steps':'minutes',period:a.period==='week'?'weekly':'daily',target:num(s.goal||a.goal||1),bonusTarget:null,unit:a.unit||metricUnits.minutes,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
}
function normalizeGoalConfig(id,cfg={}){
  id=normalizeActivityId(id); const b=baseGoalConfig(id); const out={...b,...cfg,activityId:id};
  if((id==='running'||id==='cycling') && out.metric && out.metric!=='kilometers'){ out.needsReconfiguration=true; out.migrationNotice='Skal konfigureres igen i kilometer'; out.metric='kilometers'; out.unit='km'; out.complete=false; }
  out.target=num(out.target); out.bonusTarget=out.bonusTarget===''?null:(out.bonusTarget==null?null:num(out.bonusTarget)); out.unit=out.unit||metricUnits[out.metric]||b.unit; out.period=out.period||'daily'; out.comparisonMode=out.comparisonMode||'moreIsBetter'; if(id==='mostSteps'){ out.target=0; out.complete=true; out.comparisonMode='ranking'; out.scoringMethod='ranking'; return out; }
  if(id==='dailyStepTarget') out.comparisonMode='completedDays';
  if(id==='bedtime') out.comparisonMode='earlierThanTarget';
  if(id==='strength'){ out.metric='sets'; out.unit='sæt'; }
  if(id==='socialMediaFree') out.comparisonMode='lessIsBetter'; out.scoringMethod=out.comparisonMode==='lessIsBetter'?'lessIsBetter':(out.comparisonMode==='withinRange'?'withinRange':(out.comparisonMode==='earlierThanTarget'?'earlierThanTarget':'moreIsBetter'));
  const lowerBetter=id==='bedtime'||id==='socialMediaFree';
  out.bonusTarget=null;
  out.complete=!out.needsReconfiguration && (id==='mostSteps' || !!out.target);
  return out;
}
function ensureCompetitionGoals(c){ c.activityGoals ||= {}; c.activities=sanitizeActivityIds(c.activities); c.activities.forEach(id=>{ c.activityGoals[id]=normalizeGoalConfig(id,c.activityGoals[id]); }); return c.activityGoals; }
function goalConfig(c,id){ return normalizeGoalConfig(id,(c.activityGoals||{})[id]); }
function scoreMoreIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?clamp(value/target*100,0,100):100; }
function scoreLessIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-(value-target)/target*100,0,100); }
function scoreEarlierThanTarget(value,target,tolerance=60){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-((value-target)/Math.max(1,num(tolerance)))*100,0,100); }
function scoreWithinRange(value,minimum,maximum,tolerance=0){ value=num(value); minimum=num(minimum); maximum=num(maximum); tolerance=num(tolerance); if(value>=minimum&&value<=maximum) return 100; const diff=value<minimum?minimum-value:value-maximum; return clamp(100-(diff/Math.max(1,tolerance||maximum||minimum))*100,0,100); }
function scoreConsistency(done,total,target){ const ratio=num(done)/Math.max(1,num(target)||num(total)||1); return scoreMoreIsBetter(ratio*100,100); }
function scoringLabelForGoal(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); return cfg.comparisonMode==='ranking'?'Rangliste normaliseret til 0-100':cfg.comparisonMode==='lessIsBetter'?'Mindre er bedre':cfg.comparisonMode==='completedDays'?'Dage med nået mål':cfg.comparisonMode==='earlierThanTarget'?'Til tiden':'Procent af mål'; }
function goalComplete(cfg){ return normalizeGoalConfig(cfg.activityId,cfg).complete; }
function goalSummary(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); if(cfg.deprecated) return `${activityMeta(cfg.activityId).name}: Denne aktivitet bruges ikke længere i nye konkurrencer.`; if(cfg.needsReconfiguration) return cfg.migrationNotice||'Skal konfigureres igen.'; if(cfg.activityId==='mostSteps') return `Flest skridt · Måling: ${cfg.period==='competition'?'Flest skridt i hele konkurrenceperioden':cfg.period==='daily'?'Flest skridt pr. dag':'Højeste gennemsnit pr. dag'}`; if(cfg.activityId==='dailyStepTarget') return `Dagligt skridtmål · Mål: ${fmt(cfg.target)} skridt · Scoring: Antal dage med nået mål`; if(cfg.activityId==='bedtime') return `Sengetid · Mål: senest kl. ${timeLabel(cfg.target)} · Scoring: gennemført dag`; if(cfg.activityId==='running'||cfg.activityId==='cycling') return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} km ${periodLabels[cfg.period]||cfg.period}`; if(cfg.activityId==='socialMediaFree') return `Tid på sociale medier · Mål: højst ${formatDuration(cfg.target)} ${periodLabels[cfg.period]||cfg.period} · Jo mindre jo bedre`; if(cfg.activityId==='screenFreeBeforeBed') return `Skærmfri før sengetid · Mål: ${formatDuration(cfg.target)}`; if(isDurationActivity(cfg.activityId)) return `${activityMeta(cfg.activityId).name} · Mål: ${formatDuration(cfg.target)} ${periodLabels[cfg.period]||cfg.period}`; return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} ${cfg.unit} ${periodLabels[cfg.period]||cfg.period}`; }
function newCompetitionGoalDefault(id) {
  const defaults = {
    strength: 1,
    screenFreeBeforeBed: 30,
    socialMediaFree: 60,
    running: 5,
    cycling: 10,
    dailyStepTarget: 8000
  };

  if (id === 'mostSteps') return 0;

  const value = defaults[id] ?? baseGoalConfig(id).target ?? 1;
  return isDurationActivity(id) ? durationMinutesForActivity(id, value) : value;
}
function draftGoal(id) {
  competitionDraft.activityGoals ||= {};

  if (!competitionDraft.activityGoals[id]) {
    competitionDraft.activityGoals[id] = normalizeGoalConfig(id, {
      ...baseGoalConfig(id),
      target: newCompetitionGoalDefault(id),
      legacyDefault: false,
      complete: true,
      migratedFromLegacy: false,
      needsReconfiguration: false,
      migrationNotice: ''
    });
  }

  return competitionDraft.activityGoals[id];
}
function wizardIncompleteActivities(d){ return (d.activities||[]).filter(id=>!goalComplete((d.activityGoals||{})[id]||{activityId:id,target:0})); }

function periodGoalForCompetition(id,c,date=todayKey()){ const cfg=goalConfig(c,id), end=(c.endDate&&c.endDate<date)?c.endDate:date, days=dateRange(c.startDate||end,end).length||1; if(cfg.period==='competition') return cfg.target; if(cfg.period==='weekly') return cfg.target*Math.max(1,days/7); return cfg.target*days; }
function competitionPeriodValue(id,participant,c,date=todayKey()){ const end=(c.endDate&&c.endDate<date)?c.endDate:date; return dateRange(c.startDate||end,end).reduce((s,d)=>s+rawActivityValueForParticipant(id,participant,d),0); }
function activityChips(ids,limit=3){ const safe=sanitizeActivityIds(ids); const shown=safe.slice(0,limit).map(id=>{ const a=activityMeta(id); return `<span class="chip ${isDeprecatedActivity(id)?'deprecated':''}" title="${a.description}">${a.icon} ${a.name}${isDeprecatedActivity(id)?' (udgået)':''}</span>`; }).join(''); return shown+(safe.length>limit?`<span class="chip">+${safe.length-limit} aktiviteter</span>`:''); }

function endOfCopenhagenDayIso(date){ return `${date}T23:59:59+02:00`; }
function migrateCompetitionEndAt(){ (state?.competitions||[]).forEach(c=>{ if(!c.endAt && c.endDate) c.endAt=endOfCopenhagenDayIso(c.endDate); }); }
function competitionEndTimestamp(c){ if(c?.endAt){ const t=Date.parse(c.endAt); if(Number.isFinite(t)) return t; } return Date.parse(endOfCopenhagenDayIso(c?.endDate||todayKey())); }
function competitionTimeRemaining(c, now=oneUpNowMs()){ const ms=Math.max(0,competitionEndTimestamp(c)-now); return {totalMs:ms,days:Math.floor(ms/86400000),hours:Math.floor((ms%86400000)/3600000),minutes:Math.floor((ms%3600000)/60000),seconds:Math.floor((ms%60000)/1000),finished:ms<=0}; }
function formatCompetitionRemaining(c, now=Date.now()){ const r=competitionTimeRemaining(c,now); if(r.finished) return 'Konkurrencen er afsluttet'; if(r.totalMs>=86400000) return `${r.days} ${r.days===1?'dag':'dage'} tilbage`; return `${String(r.hours).padStart(2,'0')}:${String(r.minutes).padStart(2,'0')}:${String(r.seconds).padStart(2,'0')} tilbage`; }
function updateCompetitionCountdowns(){ const els=$$('[data-competition-countdown]'); if(!els.length) return; let changed=false; els.forEach(el=>{ const c=state.competitions.find(x=>x.id===el.dataset.competitionCountdown)||{id:el.dataset.competitionCountdown,endAt:el.dataset.endAt}; const text=formatCompetitionRemaining(c); if(el.textContent!==text) el.textContent=text; if(competitionTimeRemaining(c).finished && c.status==='active' && !finishedCountdowns.has(c.id)){ finishedCountdowns.add(c.id); c.status='finished'; c.finalResults=competitionLeaderboard(c); changed=true; } }); if(changed) persist(); }
function startCompetitionCountdowns(){ clearInterval(competitionCountdownTimer); updateCompetitionCountdowns(); competitionCountdownTimer=setInterval(updateCompetitionCountdowns,1000); }
if(typeof window!=='undefined') window.addEventListener?.('beforeunload',()=>clearInterval(competitionCountdownTimer));


const ONEUP_APP_BASE_URL = 'https://nickzen108.github.io/OneUp/';
const ONEUP_PLAY_STORE_URL = '';
const INVITE_BACKEND_NOTICE = 'Invitationer deles som stabile links og koder. I den lokale demo kan modtageren kun slå invitationer op, der findes på samme enhed; synkron deling mellem forskellige telefoner kræver den planlagte Firebase/Supabase InviteRepository-adapter.';
function randomInviteToken(len=18){ const chars='ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789'; const cryptoObj=globalThis.crypto; if(cryptoObj?.randomUUID) return cryptoObj.randomUUID().replace(/-/g,'').slice(0,len); const bytes=new Uint8Array(len); if(cryptoObj?.getRandomValues) cryptoObj.getRandomValues(bytes); else for(let i=0;i<len;i++) bytes[i]=Math.floor(Math.random()*256); return Array.from(bytes,b=>chars[b%chars.length]).join(''); }
function inviteCodeFromToken(token=''){ const clean=String(token).replace(/[^a-z0-9]/gi,'').toUpperCase(); return `${(clean.slice(0,4)||'ONEU').padEnd(4,'X')}-${(clean.slice(-2)||'P1').padEnd(2,'9')}`; }
function ensureCompetitionInvite(c){ c.invite ||= {}; if(!c.invite.token){ c.invite.token=randomInviteToken(); c.invite.createdAt=new Date().toISOString(); c.invite.active=true; } c.invite.code ||= inviteCodeFromToken(c.invite.token); c.invite.active = c.invite.active!==false; return c.invite; }
function inviteKindForCompetition(c){ return isCoopCompetition(c)?'collaboration':'competition'; }
function inviteLabel(type){ return type==='collaboration'?'Samarbejde':'Konkurrence'; }
function inviteUrlFor(c){ const inv=ensureCompetitionInvite(c), type=inviteKindForCompetition(c); return `${ONEUP_APP_BASE_URL}?join=${type}&invite=${encodeURIComponent(inv.token)}`; }
function parseOneUpInviteUrl(url){ try{ const text=String(url||''); const q=text.match(/[?&]join=(competition|collaboration)&invite=([A-Za-z0-9-]{4,64})/); if(q) return {type:q[1],inviteToken:decodeURIComponent(q[2])}; const path=text.match(/(?:https:\/\/nickzen108\.github\.io\/OneUp\/|oneup:\/\/)?join\/(competition|collaboration)\/([A-Za-z0-9-]{4,64})/); if(path) return {type:path[1],inviteToken:path[2]}; const scheme=text.match(/^oneup:\/\/join\/(competition|collaboration)\/([A-Za-z0-9-]{4,64})/); if(scheme) return {type:scheme[1],inviteToken:scheme[2]}; return null; }catch{return null;} }
function findInviteByToken(token,type){ return (state.competitions||[]).find(c=>ensureCompetitionInvite(c).token===token && inviteKindForCompetition(c)===type); }
function findInviteByCode(code){ const clean=String(code||'').replace(/\s/g,'').toUpperCase(); return (state.competitions||[]).find(c=>ensureCompetitionInvite(c).code.toUpperCase()===clean); }
const InviteRepository = { createInvite(c){ ensureCompetitionInvite(c); persist(); return invitationViewModel(c); }, getInviteByToken(type,token){ const c=findInviteByToken(token,type); return c?invitationViewModel(c):null; }, joinInvite(type,token){ const c=findInviteByToken(token,type); if(!c) return {ok:false,message:'Invitationen er ikke længere gyldig'}; if(c.status==='archived'||c.deleted) return {ok:false,message:'Invitationen er ikke længere gyldig'}; if(c.status==='finished'||competitionTimeRemaining(c).finished) return {ok:false,message:isCoopCompetition(c)?'Samarbejdet er afsluttet':'Konkurrencen er afsluttet'}; if(c.maxParticipants && c.participants.length>=c.maxParticipants) return {ok:false,message:'Der er ikke plads til flere deltagere'}; if(c.creator===currentUserId) return {ok:false,message:'Du ejer allerede invitationen'}; if(c.participants.some(p=>p.id===currentUserId)) return {ok:true,already:true,message:'Du deltager allerede',competition:c}; c.participants.push({id:currentUserId,name:userName(),joinedAt:new Date().toISOString()}); addCompetitionChange(c,'tilføjede deltager via invitation','-',userName()); recalcCompetitions(); persist(); localStorage.removeItem(KEYS.pendingInvite); return {ok:true,message:'Du deltager nu',competition:c}; }, regenerateInvite(c){ const old=ensureCompetitionInvite(c).token; c.invite={token:randomInviteToken(),code:'',createdAt:new Date().toISOString(),active:true,revokedTokens:[...(c.invite.revokedTokens||[]),old]}; c.invite.code=inviteCodeFromToken(c.invite.token); addCompetitionChange(c,'oprettede nyt invitationslink',old,'nyt link'); persist(); return c.invite; } };
function invitationViewModel(c){ const inv=ensureCompetitionInvite(c), ids=sanitizeActivityIds(c.activities), first=activityMeta(ids[0]||'dailyStepTarget'); return {type:inviteKindForCompetition(c),label:inviteLabel(inviteKindForCompetition(c)),title:c.name,description:c.description||'',activity:ids.map(id=>activityMeta(id).name).join(', '),goal:ids.map(id=>goalSummary(id,goalConfig(c,id))).join(' · '),unit:first.unit||'',startDate:c.startDate,endDate:c.endDate,ownerName:(c.participants||[]).find(p=>p.id===c.creator)?.name||userName(),participantCount:(c.participants||[]).length,maxParticipants:c.maxParticipants||null,inviteToken:inv.token,inviteCode:inv.code,competitionId:c.id,status:c.status==='finished'?'udløbet':c.status}; }
function savePendingInvite(inv){ if(inv) save(KEYS.pendingInvite,{type:inv.type,inviteToken:inv.inviteToken,createdAt:new Date().toISOString()}); }
function shareTextFor(c){ const v=invitationViewModel(c), kind=v.type==='collaboration'?'samarbejdet':'konkurrencen'; return `${v.ownerName} inviterer dig til ${kind} “${v.title}” i OneUp.\n\nSe invitationen og deltag her:\n${inviteUrlFor(c)}`; }
async function copyText(text,ok='Link kopieret'){ try{ await navigator.clipboard.writeText(text); }catch{ const ta=document.createElement('textarea'); ta.value=text; document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove(); } showToast(ok,{duration:1800}); }
async function openCompetitionInviteShare(id){ const c=state.competitions.find(x=>x.id===id); if(!c) return; const url=inviteUrlFor(c), text=shareTextFor(c), vm=invitationViewModel(c); if(navigator.share){ try{ await navigator.share({title:`OneUp ${vm.label}: ${vm.title}`,text,url}); return; }catch(e){} } closeInviteSheet(); document.body.insertAdjacentHTML('beforeend',`<div id="invite-share-sheet" class="modal invite-share-backdrop" role="dialog" aria-modal="true"><div class="modal-card invite-share-sheet"><div class="card-head"><div><p class="eyebrow">Del invitation</p><h2>${escapeHtml(vm.title)}</h2><p class="muted">${escapeHtml(vm.label)} · ${escapeHtml(vm.ownerName)} inviterer · kode ${escapeHtml(vm.inviteCode)}</p></div><button type="button" class="secondary" data-invite-close>✕</button></div><p>${escapeHtml(vm.activity)} · ${escapeHtml(vm.goal)}</p><label class="field"><span>Invitationslink</span><input readonly value="${escapeHtml(url)}"></label><div class="button-row"><button data-copy-invite-link>Kopiér link</button><button class="secondary" data-copy-invite-code>Kopiér invitationskode</button></div><p class="info-box">${escapeHtml(INVITE_BACKEND_NOTICE)}</p></div></div>`); const sh=$('#invite-share-sheet'); sh.querySelector('[data-invite-close]').onclick=closeInviteSheet; sh.onclick=e=>{ if(e.target===sh) closeInviteSheet(); }; sh.querySelector('[data-copy-invite-link]').onclick=()=>copyText(url); sh.querySelector('[data-copy-invite-code]').onclick=()=>copyText(vm.inviteCode,'Invitationskode kopieret'); }
function renderInvitationScreen(inv){ const c=findInviteByToken(inv.inviteToken,inv.type); const vm=c&&invitationViewModel(c); closeInviteSheet(); document.body.insertAdjacentHTML('beforeend',`<div id="invite-share-sheet" class="modal invite-share-backdrop" role="dialog" aria-modal="true"><div class="modal-card invite-share-sheet invitation-screen"><div class="card-head"><div><p class="eyebrow">OneUp invitation</p><h2>${vm?escapeHtml(vm.title):'Invitationen er ikke længere gyldig'}</h2></div><button class="secondary" data-invite-close>Ikke nu</button></div>${vm?`<span class="chip">${vm.type==='competition'?'🏆':'🤝'} ${vm.label}</span><p><b>${escapeHtml(vm.ownerName)}</b> inviterer dig.</p><ul class="plain-list"><li>Aktivitet: ${escapeHtml(vm.activity)}</li><li>Mål: ${escapeHtml(vm.goal)} ${escapeHtml(vm.unit)}</li><li>Periode: ${escapeHtml(vm.startDate)} – ${escapeHtml(vm.endDate||'uden slutdato')}</li><li>Deltagere: ${vm.participantCount}${vm.maxParticipants?' / '+vm.maxParticipants:''}</li><li>Invitationskode: <b>${escapeHtml(vm.inviteCode)}</b></li></ul>${vm.description?`<p>${escapeHtml(vm.description)}</p>`:''}<p class="info-box">OneUp hjælper jer med sunde vaner, konkurrencer og fælles mål. Du bliver først tilmeldt, når du trykker Deltag.</p><div class="button-row"><button data-join-invite>Deltag</button><button class="secondary" data-copy-invite-code>Kopiér invitationskode</button>${ONEUP_PLAY_STORE_URL?`<a class="button" href="${ONEUP_PLAY_STORE_URL}">Hent OneUp og deltag</a>`:''}<button class="secondary" data-invite-close>Fortsæt i webudgaven</button></div><p class="muted">${escapeHtml(INVITE_BACKEND_NOTICE)}</p>`:`<p class="error">Invitationen er ikke længere gyldig.</p><button data-invite-close>Til forsiden</button>`}</div></div>`); const sh=$('#invite-share-sheet'); sh.querySelectorAll('[data-invite-close]').forEach(b=>b.onclick=()=>{ closeInviteSheet(); showPage('today'); }); sh.querySelector('[data-copy-invite-code]')?.addEventListener('click',()=>copyText(vm.inviteCode,'Invitationskode kopieret')); sh.querySelector('[data-join-invite]')?.addEventListener('click',()=>{ const res=InviteRepository.joinInvite(inv.type,inv.inviteToken); showToast(res.message); if(res.competition){ maybePromptForNotifications('accepted-invitation'); closeInviteSheet(); openCompetitionDetail(res.competition.id); } }); }
function handleIncomingInvite(inv){ if(!inv) return false; savePendingInvite(inv); renderInvitationScreen(inv); return true; }
function handleIncomingInviteUrl(url){ return handleIncomingInvite(parseOneUpInviteUrl(url)); }
function resumePendingInvite(){ const p=read(KEYS.pendingInvite,null); if(p) handleIncomingInvite({type:p.type,inviteToken:p.inviteToken}); }
function bindInviteDeepLinks(){ if(typeof location!=='undefined') handleIncomingInviteUrl(location.href); window.Capacitor?.App?.addListener?.('appUrlOpen',e=>handleIncomingInviteUrl(e.url)); window.Capacitor?.App?.addListener?.('appStateChange',({isActive})=>{ if(isActive) resumePendingInvite(); }); }
function openInviteCodeDialog(){ const code=prompt('Indtast invitationskode'); if(!code) return; const c=findInviteByCode(code); if(c) handleIncomingInvite({type:inviteKindForCompetition(c),inviteToken:ensureCompetitionInvite(c).token}); else showToast('Invitationen er ikke længere gyldig'); }

function createCompetition(cfg){ cfg={...cfg,type:normalizeCompetitionType(cfg.type)}; const ids=sanitizeActivityIds(cfg.activities||activeActivityIds()); ids.filter(id=>activities[id]).forEach(id=>{ state.activitySettings[id] ||= {...defaultActivitySettings()[id]}; state.activitySettings[id].enabled=true; }); const participants=cfg.type==='self'?[{id:currentUserId,name:userName()}]:[{id:currentUserId,name:userName()},...(cfg.participants||demoParticipants())]; const activityGoals=Object.fromEntries(ids.map(id=>[id,normalizeGoalConfig(id,(cfg.activityGoals||{})[id]||baseGoalConfig(id))])); const c={id:`comp-${Date.now()}-${Math.random().toString(16).slice(2)}`,name:cfg.name||'Ny konkurrence',type:cfg.type||'self',status:'active',creator:currentUserId,leaders:[currentUserId],participants,activities:ids,activityGoals,weighting:{mode:cfg.weightingMode||'equal',weights:cfg.weightingMode==='custom'?Object.fromEntries(ids.map(id=>[id,(cfg.weights||{})[id] ?? (id==='dailyStepTarget'?(cfg.weights||{}).steps:undefined) ?? defaultWeights(ids)[id]])):defaultWeights(ids)},scoringMethod:cfg.scoringMethod||'configuredGoals',startDate:cfg.startDate||todayKey(),endDate:cfg.endDate||day(6),endAt:cfg.endAt||endOfCopenhagenDayIso(cfg.endDate||day(6)),changeLog:[],results:{},settings:{ruleChangeMode:'fromNow',hvrReady:true,coopGoal:cfg.type==='coop'},createdAt:new Date().toISOString()}; ensureCompetitionInvite(c); state.competitions.unshift(c); addCompetitionChange(c,'oprettede konkurrencen','-',c.name); recalcCompetitions(); persist(); maybePromptForNotifications(c.type==='coop'?'first-collaboration':'first-competition'); return c; }
function isCompetitionLeader(c,uid=currentUserId){ return (c.leaders||[]).includes(uid); }
function addCompetitionChange(c,what,oldValue,newValue){ c.changeLog ||= []; c.changeLog.unshift({id:`chg-${Date.now()}-${Math.random().toString(16).slice(2)}`,at:new Date().toISOString(),leaderId:currentUserId,leaderName:userName(),what,oldValue,newValue,mode:'fromNow'}); }
function dateRange(start,end){ const out=[]; for(let d=start,guard=0; d<=end && guard<370; d=day(1,d),guard++) out.push(d); return out; }
function rawActivityValueForParticipant(id,participant,date){ const mine=valueFor(id,date); if(participant.id===currentUserId) return mine; const seed=participant.id.split('').reduce((s,ch)=>s+ch.charCodeAt(0),0)+(date||'').slice(-2)*7; const g=goalFor(id)||1; return Math.round(g*(.55+((seed%70)/100))); }
function sleepCompetitionScore(participant,date){ const base=rawActivityValueForParticipant('sleep',participant,date), g=goalFor('sleep')||8; const duration=Math.min(base/g*75,75), regularity=participant.id===currentUserId && requirementMet('sleep',date)?25:18; return clamp(duration+regularity,0,120); }
function activityEntryPoints(id,participant,date){ if(participant.id!==currentUserId) return Math.round(rawActivityValueForParticipant(id,participant,date)/Math.max(1,goalFor(id))*100); return entries(date,id).reduce((s,e)=>s+pointsForEntry(e),0); }
function baselineFor(id,participant,date){ return [7,8,9,10,11,12,13].reduce((s,o)=>s+rawActivityValueForParticipant(id,participant,day(-o,date)),0)/7 || 1; }
function competitionActivityScore(c,id,participant,date=todayKey()){ id=id==='steps'?'dailyStepTarget':normalizeActivityId(id); if(!allActivities[id]) return 0; ensureCompetitionGoals(c); const cfg=goalConfig(c,id), raw=competitionPeriodValue(id,participant,c,date), g=periodGoalForCompetition(id,c,date)||1; if(c.scoringMethod==='points') return activityEntryPoints(id,participant,date); if(c.scoringMethod==='baseline') return clamp(raw/baselineFor(id,participant,date)*100,0,100); if(c.scoringMethod==='raw') return raw; if(c.scoringMethod==='completedDays') return raw>=g?100:0; if(cfg.comparisonMode==='ranking') return normalizedRankingScore(c,id,participant,date); if(cfg.comparisonMode==='completedDays') return dailyCompletionScore(c,id,participant,date); if(cfg.comparisonMode==='lessIsBetter') return scoreLessIsBetter(raw,g,null); if(cfg.comparisonMode==='withinRange') return scoreWithinRange(raw,cfg.minimum||cfg.target,cfg.maximum||cfg.target,cfg.tolerance||0); if(id==='bedtime') return raw&&raw<=g?100:0; return scoreMoreIsBetter(raw,g,null); }
function dailyCompletionScore(c,id,participant,date=todayKey()){ const cfg=goalConfig(c,id), dates=dateRange(c.startDate||date,(c.endDate&&c.endDate<date)?c.endDate:date); const done=dates.filter(d=>rawActivityValueForParticipant(id,participant,d)>=num(cfg.target)).length; return clamp(done/Math.max(1,dates.length)*100,0,100); }
function normalizedRankingScore(c,id,participant,date=todayKey()){ const vals=(c.participants||[]).map(p=>competitionPeriodValue(id,p,c,date)); const max=Math.max(...vals,0); if(!max) return 0; return clamp(competitionPeriodValue(id,participant,c,date)/max*100,0,100); }
function weightedScore(c,participant,date=todayKey()){ const ids=sanitizeActivityIds(c.activities), weights=c.weighting?.mode==='custom'?c.weighting.weights:defaultWeights(ids); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+competitionActivityScore(c,id,participant,date)*(weights[id]||0)/100,0)); }
function participantDays(c,p){ return dateRange(c.startDate, (c.endDate&&c.endDate<todayKey())?c.endDate:todayKey()).filter(d=>sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))).length; }
function participantStreak(c,p){ let n=0; for(let i=0;i<120;i++){ const d=day(-i); if(d<c.startDate) break; if(sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))) n++; else break; } return n; }
function competitionLeaderboard(c,sort='score',friendsOnly=false){ const rows=(c.participants||[]).filter(p=>!friendsOnly||p.friend||p.id===currentUserId).map(p=>{ const ids=sanitizeActivityIds(c.activities); const per=Object.fromEntries(ids.map(id=>[id,competitionActivityScore(c,id,p)])); const score=weightedScore(c,p), prev=weightedScore(c,p,day(-1)); return {participant:p,perActivity:per,score,change:score-prev,completedDays:participantDays(c,p),streak:participantStreak(c,p),consistency:participantDays(c,p)*10,baseline:Object.values(per).reduce((a,b)=>a+b,0)/(ids.length||1)}; }); const key=sort==='completedDays'?'completedDays':sort==='consistency'?'consistency':sort==='baseline'?'baseline':sanitizeActivityIds(c.activities).includes(sort)?null:'score'; return rows.sort((a,b)=> key?b[key]-a[key]:(b.perActivity[sort]||0)-(a.perActivity[sort]||0)).map((r,i)=>({...r,rank:i+1})); }
function recalcCompetitions(){ (state.competitions||[]).forEach(c=>{ c.activities=sanitizeActivityIds(c.activities); ensureCompetitionGoals(c); c.weighting ||= {mode:'equal',weights:defaultWeights(c.activities)}; if(c.status==='active' && competitionEndTimestamp(c)<=oneUpNowMs()){ c.status='finished'; c.finalResults=competitionLeaderboard(c); } c.results={leaderboard:competitionLeaderboard(c),updatedAt:new Date().toISOString(),userScore:weightedScore(c,{id:currentUserId,name:userName()})}; }); }
function archiveCompetition(id){ const c=state.competitions.find(x=>x.id===id); if(c){ c.status='archived'; addCompetitionChange(c,'arkiverede konkurrencen',c.status,'archived'); persist(); render(); } }
function removeLeader(c,uid){ if((c.leaders||[]).length<=1) { alert('Der skal altid være mindst én leder. Udnævn en anden leder først.'); return false; } c.leaders=c.leaders.filter(id=>id!==uid); addCompetitionChange(c,'fjernede lederstatus',uid,'ikke leder'); persist(); render(); return true; }
function ensureCompetitionWizard(){ if($('#competition-wizard')) return; document.body?.insertAdjacentHTML?.('beforeend','<div id="competition-wizard" class="modal" hidden></div>'); }
