function bindGoalControls(container=document,step=1){ const q=s=>Array.from(container.querySelectorAll(s)); q('[data-goal-preset]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.goalPreset); cfg.target=num(b.dataset.value); cfg.unit=metricUnits[cfg.metric]||cfg.unit; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.goalPreset); }); q('[data-step-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const id=b.dataset.stepGoal, cfg=draftGoal(id), min=num(b.dataset.min), max=num(b.dataset.max), delta=Number(b.dataset.delta)||1; const raw = Number(cfg.target); const current = Number.isFinite(raw) ? raw : min; const next = clamp(current + delta, min, max); setDraftGoalValue(id,next,'target',min,max); updateGoalEditorUi(id); }); q('[data-goal-segment]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.goalSegment); cfg[b.dataset.field]=b.dataset.value; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.goalSegment); }); q('[data-open-picker]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); openGoalPicker(b.dataset.openPicker,step); }); q('[data-time-field]').forEach(i=>i.onchange=()=>{ const cfg=draftGoal(i.dataset.timeField), [h,m]=(i.value||'00:00').split(':').map(Number); cfg[i.dataset.field]=h+(m||0)/60; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.timeField); }); q('[data-use-personal-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const cfg=draftGoal(b.dataset.usePersonalGoal); cfg.target=goalFor(b.dataset.usePersonalGoal); cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.usePersonalGoal); }); q('[data-custom-goal]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const v=prompt('Eget mål',''); if(v!==null){ const cfg=draftGoal(b.dataset.customGoal); cfg.target=num(v); cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.customGoal); }}); q('[data-integer-input]').forEach(i=>i.oninput=()=>{ const clean=i.value.replace(/\D/g,''); if(i.value!==clean) i.value=clean; }); q('[data-decimal-input]').forEach(i=>i.oninput=()=>{ let clean=i.value.replace(',', '.').replace(/[^0-9.]/g,''); const parts=clean.split('.'); if(parts.length>2) clean=`${parts.shift()}.${parts.join('')}`; if(i.value!==clean) i.value=clean; }); q('[data-goal-field]').forEach(i=>{ i.onchange=()=>{ if(i.dataset.integerInput==='true') i.value=i.value.replace(/\D/g,''); if(i.dataset.decimalInput==='true'){ let clean=i.value.replace(',', '.').replace(/[^0-9.]/g,''); const parts=clean.split('.'); if(parts.length>2) clean=`${parts.shift()}.${parts.join('')}`; i.value=clean; } const cfg=draftGoal(i.dataset.goalField), f=i.dataset.field; if(f==='target'||f==='bonusTarget'||f==='tolerance') cfg[f]=i.value===''?null:num(i.value); else if(f==='bedtimeStart'||f==='bedtimeEnd'){ cfg.bedtimeWindow ||= {}; cfg.bedtimeWindow[f==='bedtimeStart'?'start':'end']=i.value; } else cfg[f]=i.value; if(f==='metric') cfg.unit=metricUnits[cfg.metric]||cfg.unit; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.goalField); }; i.oninput=i.onchange; }); q('[data-custom-time]').forEach(b=>b.onclick=e=>{ consumeInteraction(e); const v=prompt('Eget tidspunkt (HH:MM)','22:30'); if(v){ const [h,m]=v.split(':').map(Number); const cfg=draftGoal(b.dataset.customTime); cfg.target=h+(m||0)/60; cfg.legacyDefault=false; cfg.complete=goalComplete(cfg); updateGoalEditorUi(b.dataset.customTime); }}); q('[data-sleep-criterion]').forEach(i=>i.onchange=()=>{ const cfg=draftGoal(i.dataset.sleepCriterion); const vals=Array.from(container.querySelectorAll('[data-sleep-criterion]')).filter(x=>x.checked).map(x=>x.value); cfg.criteria=vals; cfg.comparisonMode='withinRange'; cfg.complete=goalComplete(cfg); updateGoalEditorUi(i.dataset.sleepCriterion); }); }
