function hideToast(){ const toast=$('#app-toast'); if(toast){ toast.classList.remove('visible'); toast.hidden=true; } if(toastTimer){ clearTimeout(toastTimer); toastTimer=null; } }
function showToast(message, options={}){
  const toast=$('#app-toast'); if(!toast) return;
  if(toastTimer){ clearTimeout(toastTimer); toastTimer=null; }
  toast.textContent=message; toast.hidden=false;
  toast.classList.remove('visible');
  const raf=typeof requestAnimationFrame==='function'?requestAnimationFrame:(fn=>setTimeout(fn,0));
  raf(()=>toast.classList.add('visible'));
  toastTimer=setTimeout(()=>{ toast.classList.remove('visible'); toastTimer=setTimeout(()=>{ toast.hidden=true; toastTimer=null; }, options.fadeMs ?? 200); }, options.duration ?? 2800);
  return toast;
}
function showPage(id){ hideToast(); if(id==='competition') id='friends'; if(id==='connections') renderConnections(); if(typeof history!=='undefined' && history.pushState && !showPage.silent){ history.pushState({page:id},'',`#${id}`); } if(id==='today') setCompetitionDetailMode(false); if(id==='friends' && !selectedCompetitionId) setCompetitionDetailMode(false); $$('.page').forEach(p=>p.classList.toggle('active',p.dataset.page===id)); $$('[data-main-nav]').forEach(b=>b.classList.toggle('active',b.dataset.mainNav===id)); }
function saveProfileDraft(){
  const f=$('#profile-form'); if(!f) return;
  const fd=new FormData(f), p=state.profile;
  if(fd.has('name')) p.name=String(fd.get('name')||'');
  if(fd.has('birthDate')) p.birthDate=String(fd.get('birthDate')||'');
  if(fd.has('countryCode')) p.countryCode=String(fd.get('countryCode')||'');
  if(fd.has('biologicalSex')) p.biologicalSex=String(fd.get('biologicalSex')||'');
  if(fd.has('language')) p.language=String(fd.get('language')||'');
  if(fd.has('heightCm')) p.heightCm=fd.get('heightCm')===''?'':num(fd.get('heightCm'));
  if(fd.has('heightFeet')||fd.has('heightInches')){ const ft=fd.get('heightFeet'), inch=fd.get('heightInches'); if(ft!==''||inch!=='') p.heightCm=feetInchesToCm(ft,inch); }
  if(fd.has('weightKg')) p.weightKg=fd.get('weightKg')===''?'':num(fd.get('weightKg'));
  if(fd.has('weightLb')) p.weightKg=fd.get('weightLb')===''?'':lbToKg(fd.get('weightLb'));
}
function saveProfileFromForm(form){
  const submitButton=form.querySelector('[type="submit"]'); if(submitButton) submitButton.disabled=true;
  const fd=new FormData(form), p=state.profile, msg=$('#profile-message'), name=String(fd.get('name')||'').trim();
  if(!name){ if(msg){ msg.className='error'; msg.textContent='Skriv dit navn eller kaldenavn.'; } $('#profile-name')?.focus(); if(submitButton) submitButton.disabled=false; return; }
  const birthDate=String(fd.get('birthDate')||''); if(birthDate && birthDate>todayKey()){ if(msg){ msg.className='error'; msg.textContent='Fødselsdato må ikke ligge i fremtiden.'; } if(submitButton) submitButton.disabled=false; return; }
  let heightCm='', weightKg='';
  if(state.settings.units==='imperial'){
    const ft=fd.get('heightFeet'), inch=fd.get('heightInches');
    if(ft!==''||inch!==''){ if(num(ft)<1||num(ft)>8||num(inch)>11){ if(msg){ msg.className='error'; msg.textContent='Højde skal være 1–8 fod og 0–11 tommer.'; } if(submitButton) submitButton.disabled=false; return; } heightCm=feetInchesToCm(ft,inch); }
    const lb=fd.get('weightLb'); if(lb!=='') weightKg=lbToKg(lb);
  } else {
    const cm=fd.get('heightCm'); if(cm!==''){ if(num(cm)<50||num(cm)>250){ if(msg){ msg.className='error'; msg.textContent='Højde skal være mellem 50 og 250 cm.'; } if(submitButton) submitButton.disabled=false; return; } heightCm=num(cm); }
    const kg=fd.get('weightKg'); if(kg!=='') weightKg=num(kg);
  }
  p.name=name; p.birthDate=birthDate; if(birthDate) delete p.birthYear;
  if(heightCm==='') delete p.heightCm; else p.heightCm=Math.round(heightCm*10)/10;
  if(weightKg==='') delete p.weightKg; else p.weightKg=Math.round(weightKg*10)/10;
  p.countryCode=String(fd.get('countryCode')||''); p.biologicalSex=String(fd.get('biologicalSex')||''); p.language=String(fd.get('language')||'da');
  const nextSettings={...state.settings};
  nextSettings.language=p.language;
  nextSettings.units=state.settings.units==='imperial'?'imperial':'metric';
  ['vibration','sounds','voice'].forEach(k=>{ const el=form.querySelector(`[data-setting="${k}"]`); if(el) nextSettings[k]=!!el.checked; });
  const weekStarts=form.querySelector('[data-setting="weekStarts"]'); if(weekStarts) nextSettings.weekStarts=weekStarts.value==='sunday'?'sunday':'monday';
  state.settings=nextSettings;
  normalizeSharing();
  const master=form.querySelector('[data-sharing-master]');
  if(master) state.profile.sharing.shareDailyScores=!!master.checked;
  form.querySelectorAll('[data-sharing-metric]').forEach(el=>{ state.profile.sharing.metrics[el.dataset.sharingMetric]=!!el.checked; });
  persist();
  if(msg){ msg.className='muted'; msg.textContent=''; }
  showToast('✓ Profil og indstillinger er gemt');
  if(submitButton){
    submitButton.disabled=false;
    submitButton.classList.add('saved');
    if(saveButtonTimer) clearTimeout(saveButtonTimer);
    saveButtonTimer=setTimeout(()=>{ submitButton.classList.remove('saved'); saveButtonTimer=null; }, 1300);
  }
}
function bindStatic(){ document.addEventListener?.('keydown',e=>{ if(e.key==='Escape'){ closeNotificationPrompt(); closeHealthConnectIntro(); closeHomeCardMenu(); closeInviteSheet(); closeCompetitionCreator(); } }); window.addEventListener?.('popstate',e=>{ if(healthConnectIntro){ closeHealthConnectIntro(true); return; } if(openHomeCardMenu){ closeHomeCardMenu(true); return; } showPage.silent=true; showPage(e.state?.page||location.hash.replace('#','')||'today'); showPage.silent=false; }); const profileButton=document.querySelector('[data-open-profile]'); if(profileButton) profileButton.onclick=openProfileFromHeader; $$('[data-main-nav]').forEach(b=>b.onclick=()=>{ selectedCompetitionId=null; showPage(b.dataset.mainNav); }); $$('[data-page-back]').forEach(b=>b.onclick=()=>{ if(typeof history!=='undefined'&&history.length>1) history.back(); else showPage('activities'); }); $$('[data-nav]').forEach(b=>b.onclick=()=>{ if(b.dataset.nav==='competition') selectedCompetitionId=null; if(b.dataset.nav==='today') selectedCompetitionId=null; showPage(b.dataset.nav); }); $$('[data-competition]').forEach(b=>b.onclick=()=>{ $$('[data-competition]').forEach(x=>x.classList.remove('active')); b.classList.add('active'); const others=$('#competition-others'), self=$('#competition-self'); if(others) others.hidden=b.dataset.competition!=='others'; if(self) self.hidden=b.dataset.competition!=='self';}); const cg=$('#create-group'); if(cg) cg.onclick=()=>{ const msg=$('#group-message'); if(msg) msg.textContent='Rigtige grupper og invitationer kræver login og kommer i en senere version.'; }; const pf=$('#profile-form'); if(pf) pf.onsubmit=e=>{e.preventDefault(); saveProfileFromForm(e.target);}; const df=$('#development-filter'); if(df) df.onchange=renderDevelopment; const ct=$('#competition-type'); if(ct) ct.onchange=renderCompetition; }
